package com.example.desaappsavaloskoortuzarvargas.data.api
import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.withContext import kotlinx.serialization.json.Json import kotlinx.serialization.json.JsonObject import kotlinx.serialization.json.jsonArray import kotlinx.serialization.json.jsonObject import kotlinx.serialization.json.jsonPrimitive import java.net.HttpURLConnection import java.net.URL import java.net.URLEncoder
/** * Service to fetch prices from Battle.net / Blizzard Shop for Argentina. * * Battle.net does not have an official public pricing API, but their * web shop loads product data via accessible JSON endpoints. * We attempt to use Battle.net's shop search API with Argentine locale. * * Note: Battle.net only sells Blizzard/Activision games (Diablo, WoW, * Overwatch, CoD, StarCraft, etc.). Many of these are also on Steam. * If this service fails, those games' prices are still available * through the Steam/Epic services. */ class BattleNetPriceService {
private val json = Json { ignoreUnknownKeys = true }
/** * Search for a game on the Battle.net shop and return the Argentine price. * Uses Blizzard's shop catalog API with AR region. */ suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) { try { val encoded = URLEncoder.encode(title, "UTF-8") // Blizzard shop catalog endpoint with AR locale val url = URL( "https://us.shop.battle.net/api/catalog?q=$encoded&locale=es-AR&country=AR" ) val conn = url.openConnection() as HttpURLConnection conn.requestMethod = "GET" conn.connectTimeout = 8000 conn.readTimeout = 8000 conn.setRequestProperty("Accept", "application/json") conn.setRequestProperty("User-Agent", "Mozilla/5.0")
if (conn.responseCode == 200) { val response = conn.inputStream.bufferedReader().readText() val parsed = json.decodeFromString<JsonObject>(response)
val products = parsed["products"]?.jsonArray ?: return@withContext null if (products.isEmpty()) return@withContext null
val firstProduct = products[0].jsonObject val productTitle = firstProduct["name"]?.jsonPrimitive?.content ?: title val priceObj = firstProduct["price"]?.jsonObject
val currentPrice = priceObj?.get("amount")?.jsonPrimitive?.content ?.toFloatOrNull() val originalPrice = priceObj?.get("originalAmount")?.jsonPrimitive?.content ?.toFloatOrNull() val currency = priceObj?.get("currency")?.jsonPrimitive?.content ?: "USD" val productSlug = firstProduct["slug"]?.jsonPrimitive?.content ?: ""
if (currentPrice == null) return@withContext null
val msrp = originalPrice ?: currentPrice val discountPct = if (msrp > 0 && currentPrice < msrp) { ((1 - currentPrice / msrp) * 100).toInt() } else 0
StorePrice( storeName = "Battle.net", currentPrice = currentPrice, originalPrice = msrp, discountPercent = discountPct, currency = currency, isFree = currentPrice == 0f, storeUrl = "https://us.shop.battle.net/es-ar/product/$productSlug" ) } else null } catch (_: Exception) { null } } }

package com.example.desaappsavaloskoortuzarvargas.data.api
import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.withContext import kotlinx.serialization.json.Json import kotlinx.serialization.json.JsonObject import kotlinx.serialization.json.jsonArray import kotlinx.serialization.json.jsonObject import kotlinx.serialization.json.jsonPrimitive import java.net.HttpURLConnection import java.net.URL import java.net.URLEncoder
/** * Service to fetch prices from Battle.net / Blizzard Shop for Argentina. * * Battle.net does not have an official public pricing API, but their * web shop loads product data via accessible JSON endpoints. * We attempt to use Battle.net's shop search API with Argentine locale. * * Note: Battle.net only sells Blizzard/Activision games (Diablo, WoW, * Overwatch, CoD, StarCraft, etc.). Many of these are also on Steam. * If this service fails, those games' prices are still available * through the Steam/Epic services. */ class BattleNetPriceService {
private val json = Json { ignoreUnknownKeys = true }
/** * Search for a game on the Battle.net shop and return the Argentine price. * Uses Blizzard's shop catalog API with AR region. */ suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) { try { val encoded = URLEncoder.encode(title, "UTF-8") // Blizzard shop catalog endpoint with AR locale val url = URL( "https://us.shop.battle.net/api/catalog?q=$encoded&locale=es-AR&country=AR" ) val conn = url.openConnection() as HttpURLConnection conn.requestMethod = "GET" conn.connectTimeout = 8000 conn.readTimeout = 8000 conn.setRequestProperty("Accept", "application/json") conn.setRequestProperty("User-Agent", "Mozilla/5.0")
if (conn.responseCode == 200) { val response = conn.inputStream.bufferedReader().readText() val parsed = json.decodeFromString<JsonObject>(response)
val products = parsed["products"]?.jsonArray ?: return@withContext null if (products.isEmpty()) return@withContext null
val firstProduct = products[0].jsonObject val priceObj = firstProduct["price"]?.jsonObject
val currentPrice = priceObj?.get("amount")?.jsonPrimitive?.content ?.toFloatOrNull() val originalPrice = priceObj?.get("originalAmount")?.jsonPrimitive?.content ?.toFloatOrNull() val currency = priceObj?.get("currency")?.jsonPrimitive?.content ?: "USD" val productSlug = firstProduct["slug"]?.jsonPrimitive?.content ?: ""
if (currentPrice == null) return@withContext null
val msrp = originalPrice ?: currentPrice val discountPct = if (msrp > 0 && currentPrice < msrp) { ((1 - currentPrice / msrp) * 100).toInt() } else 0
StorePrice( storeName = "Battle.net", currentPrice = currentPrice, originalPrice = msrp, discountPercent = discountPct, currency = currency, isFree = currentPrice == 0f, storeUrl = if (productSlug.isNotEmpty()) { "https://us.shop.battle.net/es-ar/product/$productSlug" } else { val encoded = URLEncoder.encode(title, "UTF-8") "https://us.shop.battle.net/es-ar?q=$encoded" } ) } else null } catch (_: Exception) { null } } }

package com.example.desaappsavaloskoortuzarvargas.data.api
import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.withContext import kotlinx.serialization.json.Json import kotlinx.serialization.json.JsonObject import kotlinx.serialization.json.jsonArray import kotlinx.serialization.json.jsonObject import kotlinx.serialization.json.jsonPrimitive import java.net.HttpURLConnection import java.net.URL import java.net.URLEncoder
/** * Service to fetch prices from the EA App (formerly Origin) for Argentina. * * EA's public API is limited, but their storefront exposes some * accessible endpoints. We attempt to use EA's search API with * Argentine country code. * * Note: Most EA games are also available on Steam and Epic Games, * so if this service fails, those stores will typically cover EA titles. */ class EAPriceService {
private val json = Json { ignoreUnknownKeys = true }
/** * Search for a game on the EA store and return the Argentine price. * Attempts to use EA's storefront API with AR country code. */ suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) { try { val encoded = URLEncoder.encode(title, "UTF-8") // EA's search/catalog API endpoint val url = URL( "https://api2.origin.com/ecommerce2/public/supercat/AR/es_AR?searchTerm=$encoded" ) val conn = url.openConnection() as HttpURLConnection conn.requestMethod = "GET" conn.connectTimeout = 8000 conn.readTimeout = 8000 conn.setRequestProperty("Accept", "application/json") conn.setRequestProperty("User-Agent", "Mozilla/5.0")
if (conn.responseCode == 200) { val response = conn.inputStream.bufferedReader().readText() val parsed = json.decodeFromString<JsonObject>(response)
// Origin API response structure varies — try common patterns val offers = parsed["offers"]?.jsonArray ?: parsed["games"]?.jsonArray ?: return@withContext null
if (offers.isEmpty()) return@withContext null
val firstOffer = offers[0].jsonObject val gameName = firstOffer["displayName"]?.jsonPrimitive?.content ?: firstOffer["name"]?.jsonPrimitive?.content ?: title val priceObj = firstOffer["pricing"]?.jsonObject ?: firstOffer["price"]?.jsonObject
val currentPrice = priceObj?.get("finalPrice")?.jsonPrimitive?.content ?.toFloatOrNull() ?: priceObj?.get("currentPrice")?.jsonPrimitive?.content?.toFloatOrNull() val originalPrice = priceObj?.get("basePrice")?.jsonPrimitive?.content ?.toFloatOrNull() ?: priceObj?.get("originalPrice")?.jsonPrimitive?.content?.toFloatOrNull() val currency = priceObj?.get("currency")?.jsonPrimitive?.content ?: "USD" val offerId = firstOffer["offerId"]?.jsonPrimitive?.content ?: ""
if (currentPrice == null) return@withContext null
// EA prices from Origin API are typically in cents val currentPriceFloat = if (currentPrice > 1000) currentPrice / 100f else currentPrice val originalPriceFloat = if ((originalPrice ?: 0f) > 1000) (originalPrice ?: currentPrice) / 100f else (originalPrice ?: currentPrice)
val discountPct = if (originalPriceFloat > 0 && currentPriceFloat < originalPriceFloat) { ((1 - currentPriceFloat / originalPriceFloat) * 100).toInt() } else 0
StorePrice( storeName = "EA", currentPrice = currentPriceFloat, originalPrice = originalPriceFloat, discountPercent = discountPct, currency = currency, isFree = currentPriceFloat == 0f, storeUrl = "https://www.ea.com/es-ar/games/$offerId" ) } else null } catch (_: Exception) { null } } }

package com.example.desaappsavaloskoortuzarvargas.data.api
import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.withContext import kotlinx.serialization.json.Json import kotlinx.serialization.json.JsonObject import kotlinx.serialization.json.jsonArray import kotlinx.serialization.json.jsonObject import kotlinx.serialization.json.jsonPrimitive import java.net.HttpURLConnection import java.net.URL import java.net.URLEncoder
/** * Service to fetch prices from the EA App (formerly Origin) for Argentina. * * EA's public API is limited, but their storefront exposes some * accessible endpoints. We attempt to use EA's search API with * Argentine country code. * * Note: Most EA games are also available on Steam and Epic Games, * so if this service fails, those stores will typically cover EA titles. */ class EAPriceService {
private val json = Json { ignoreUnknownKeys = true }
/** * Search for a game on the EA store and return the Argentine price. * Attempts to use EA's storefront API with AR country code. */ suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) { try { val encoded = URLEncoder.encode(title, "UTF-8") // EA's search/catalog API endpoint val url = URL( "https://api2.origin.com/ecommerce2/public/supercat/AR/es_AR?searchTerm=$encoded" ) val conn = url.openConnection() as HttpURLConnection conn.requestMethod = "GET" conn.connectTimeout = 8000 conn.readTimeout = 8000 conn.setRequestProperty("Accept", "application/json") conn.setRequestProperty("User-Agent", "Mozilla/5.0")
if (conn.responseCode == 200) { val response = conn.inputStream.bufferedReader().readText() val parsed = json.decodeFromString<JsonObject>(response)
// Origin API response structure varies — try common patterns val offers = parsed["offers"]?.jsonArray ?: parsed["games"]?.jsonArray ?: return@withContext null
if (offers.isEmpty()) return@withContext null
val firstOffer = offers[0].jsonObject val gameName = firstOffer["displayName"]?.jsonPrimitive?.content ?: firstOffer["name"]?.jsonPrimitive?.content ?: title val priceObj = firstOffer["pricing"]?.jsonObject ?: firstOffer["price"]?.jsonObject
val currentPrice = priceObj?.get("finalPrice")?.jsonPrimitive?.content ?.toFloatOrNull() ?: priceObj?.get("currentPrice")?.jsonPrimitive?.content?.toFloatOrNull() val originalPrice = priceObj?.get("basePrice")?.jsonPrimitive?.content ?.toFloatOrNull() ?: priceObj?.get("originalPrice")?.jsonPrimitive?.content?.toFloatOrNull() val currency = priceObj?.get("currency")?.jsonPrimitive?.content ?: "USD"
if (currentPrice == null) return@withContext null
// EA prices from Origin API are typically in cents val currentPriceFloat = if (currentPrice > 1000) currentPrice / 100f else currentPrice val originalPriceFloat = if ((originalPrice ?: 0f) > 1000) (originalPrice ?: currentPrice) / 100f else (originalPrice ?: currentPrice)
val discountPct = if (originalPriceFloat > 0 && currentPriceFloat < originalPriceFloat) { ((1 - currentPriceFloat / originalPriceFloat) * 100).toInt() } else 0
StorePrice( storeName = "EA", currentPrice = currentPriceFloat, originalPrice = originalPriceFloat, discountPercent = discountPct, currency = currency, isFree = currentPriceFloat == 0f, storeUrl = run { // offerId from Origin API (e.g. "Origin.OFR.50.0001066") is not a URL slug. // Use EA App's search instead so the user lands near the game. val encoded = URLEncoder.encode(gameName.ifBlank { title }, "UTF-8") "https://www.ea.com/search#category=mlbgame&q=$encoded" } ) } else null } catch (_: Exception) { null } } }

package com.example.desaappsavaloskoortuzarvargas.data.api

import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import kotlinx.serialization.Serializable
import kotlinx.serialization.json.Json
import java.net.HttpURLConnection
import java.net.URL

// ── Epic Games Store GraphQL response models ──

@Serializable
data class EpicGraphQLResponse(
    val data: EpicCatalogData? = null
)

@Serializable
data class EpicCatalogData(
    val Catalog: EpicCatalog? = null
)

@Serializable
data class EpicCatalog(
    val searchStore: EpicSearchStore? = null
)

@Serializable
data class EpicSearchStore(
    val elements: List<EpicElement> = emptyList()
)

@Serializable
data class EpicKeyImage(
    val type: String = "",
    val url: String = ""
)

@Serializable
data class EpicElement(
    val title: String = "",
    val urlSlug: String = "",
    val price: EpicPriceInfo? = null,
    val keyImages: List<EpicKeyImage> = emptyList(),
    val promotions: EpicPromotions? = null
)

@Serializable
data class EpicPromotions(
    val promotionalOffers: List<EpicPromotionalOffer> = emptyList(),
    val upcomingPromotionalOffers: List<EpicPromotionalOffer> = emptyList()
)

@Serializable
data class EpicPromotionalOffer(
    val promotionalOffers: List<EpicPromotionDetail> = emptyList()
)

@Serializable
data class EpicPromotionDetail(
    val startDate: String = "",
    val endDate: String = ""
)

@Serializable
data class EpicPriceInfo(
    val totalPrice: EpicTotalPrice? = null
)

@Serializable
data class EpicTotalPrice(
    val originalPrice: Int = 0,    // In cents (e.g., 879900 = ARS 8799.00)
    val discountPrice: Int = 0,
    val discount: Int = 0,         // Discount amount in cents
    val currencyCode: String = "ARS",
    val fmtPrice: EpicFmtPrice? = null
)

@Serializable
data class EpicFmtPrice(
    val originalPrice: String = "",
    val discountPrice: String = ""
)

/**
 * Service to fetch REAL Argentine prices from the Epic Games Store.
 *
 * Uses Epic's public GraphQL API with country=AR to get the actual
 * price in ARS that an Argentine user sees on the store.
 *
 * Endpoint: https://graphql.epicgames.com/graphql
 */
class EpicPriceService {

    private val json = Json { ignoreUnknownKeys = true }

    private val searchQuery = """
        query searchStoreQuery(${'$'}country: String!, ${'$'}keywords: String!, ${'$'}count: Int) {
            Catalog {
                searchStore(
                    country: ${'$'}country,
                    keywords: ${'$'}keywords,
                    count: ${'$'}count,
                    category: "games/edition/base",
                    sortBy: "relevancy",
                    sortDir: "DESC"
                ) {
                    elements {
                        title
                        urlSlug
                        keyImages {
                            type
                            url
                        }
                        price(country: ${'$'}country) {
                            totalPrice {
                                originalPrice
                                discountPrice
                                discount
                                currencyCode
                                fmtPrice(locale: "es-AR") {
                                    originalPrice
                                    discountPrice
                                }
                            }
                        }
                        promotions {
                            promotionalOffers {
                                promotionalOffers {
                                    startDate
                                    endDate
                                }
                            }
                        }
                    }
                }
            }
        }
    """.trimIndent()

    /**
     * Search for a game on the Epic Games Store and return the Argentine price.
     * Returns null if the game is not found or an error occurs.
     */
    suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) {
        try {
            val requestBody = json.encodeToString(
                kotlinx.serialization.json.JsonObject.serializer(),
                kotlinx.serialization.json.buildJsonObject {
                    put("query", kotlinx.serialization.json.JsonPrimitive(searchQuery))
                    put("variables", kotlinx.serialization.json.buildJsonObject {
                        put("country", kotlinx.serialization.json.JsonPrimitive("AR"))
                        put("keywords", kotlinx.serialization.json.JsonPrimitive(title))
                        put("count", kotlinx.serialization.json.JsonPrimitive(3))
                    })
                }
            )

            val url = URL("https://graphql.epicgames.com/graphql")
            val conn = url.openConnection() as HttpURLConnection
            conn.requestMethod = "POST"
            conn.connectTimeout = 10000
            conn.readTimeout = 10000
            conn.setRequestProperty("Content-Type", "application/json")
            conn.setRequestProperty("Accept", "application/json")
            conn.doOutput = true
            conn.outputStream.bufferedWriter().use { it.write(requestBody) }

            if (conn.responseCode == 200) {
                val response = conn.inputStream.bufferedReader().readText()
                val parsed = json.decodeFromString<EpicGraphQLResponse>(response)
                val elements = parsed.data?.Catalog?.searchStore?.elements ?: return@withContext null

                // Find the best match by title
                val match = elements.firstOrNull { element ->
                    element.title.equals(title, ignoreCase = true)
                } ?: elements.firstOrNull() ?: return@withContext null

                val totalPrice = match.price?.totalPrice ?: return@withContext null

                // Extract a landscape image from Epic's keyImages
                val epicImageUrl = match.keyImages.firstOrNull {
                    it.type == "DieselStoreFrontWide" || it.type == "OfferImageWide"
                }?.url ?: match.keyImages.firstOrNull {
                    it.type == "DieselGameBoxWide" || it.type == "Thumbnail"
                }?.url ?: match.keyImages.firstOrNull()?.url ?: ""

                // Epic returns 0 for free games
                val isFree = totalPrice.originalPrice == 0 && totalPrice.discountPrice == 0
                val discountPct = if (totalPrice.originalPrice > 0) {
                    ((totalPrice.discount.toFloat() / totalPrice.originalPrice) * 100).toInt()
                } else 0

                // Extract promotion end date if available
                val promoEndTs = try {
                    val endDateStr = match.promotions
                        ?.promotionalOffers?.firstOrNull()
                        ?.promotionalOffers?.firstOrNull()
                        ?.endDate
                    if (!endDateStr.isNullOrEmpty()) {
                        // Epic dates are ISO 8601: "2026-06-05T15:00:00.000Z"
                        val sdf = java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'", java.util.Locale.US)
                        sdf.timeZone = java.util.TimeZone.getTimeZone("UTC")
                        sdf.parse(endDateStr)?.time
                    } else null
                } catch (_: Exception) { null }

                StorePrice(
                    storeName = "Epic Games",
                    currentPrice = totalPrice.discountPrice / 100f,
                    originalPrice = totalPrice.originalPrice / 100f,
                    discountPercent = discountPct,
                    currency = totalPrice.currencyCode,
                    isFree = isFree,
                    storeUrl = "https://store.epicgames.com/es-AR/p/${match.urlSlug}",
                    formattedPrice = totalPrice.fmtPrice?.discountPrice ?: "",
                    formattedOriginal = totalPrice.fmtPrice?.originalPrice ?: "",
                    imageUrl = epicImageUrl,
                    discountEndTimestamp = promoEndTs
                )
            } else null
        } catch (_: Exception) {
            null
        }
    }

    /**
     * Fetch ONLY the game image from Epic (lightweight, no price data).
     * Used at catalog load time for non-Steam games to populate their images.
     * Prefers wide/landscape images similar to Steam headers.
     */
    suspend fun fetchGameImage(title: String): String? = withContext(Dispatchers.IO) {
        try {
            val imageQuery = """
                query searchStoreQuery(${'$'}keywords: String!, ${'$'}count: Int) {
                    Catalog {
                        searchStore(
                            country: "US",
                            keywords: ${'$'}keywords,
                            count: ${'$'}count,
                            category: "games/edition/base",
                            sortBy: "relevancy",
                            sortDir: "DESC"
                        ) {
                            elements {
                                title
                                keyImages { type url }
                            }
                        }
                    }
                }
            """.trimIndent()

            val requestBody = json.encodeToString(
                kotlinx.serialization.json.JsonObject.serializer(),
                kotlinx.serialization.json.buildJsonObject {
                    put("query", kotlinx.serialization.json.JsonPrimitive(imageQuery))
                    put("variables", kotlinx.serialization.json.buildJsonObject {
                        put("keywords", kotlinx.serialization.json.JsonPrimitive(title))
                        put("count", kotlinx.serialization.json.JsonPrimitive(3))
                    })
                }
            )

            val url = URL("https://graphql.epicgames.com/graphql")
            val conn = url.openConnection() as HttpURLConnection
            conn.requestMethod = "POST"
            conn.connectTimeout = 10000
            conn.readTimeout = 10000
            conn.setRequestProperty("Content-Type", "application/json")
            conn.setRequestProperty("Accept", "application/json")
            conn.doOutput = true
            conn.outputStream.bufferedWriter().use { it.write(requestBody) }

            if (conn.responseCode == 200) {
                val response = conn.inputStream.bufferedReader().readText()
                val parsed = json.decodeFromString<EpicGraphQLResponse>(response)
                val elements = parsed.data?.Catalog?.searchStore?.elements ?: return@withContext null

                val match = elements.firstOrNull { it.title.equals(title, ignoreCase = true) }
                    ?: elements.firstOrNull() ?: return@withContext null

                // Prefer wide/landscape images (like Steam headers)
                match.keyImages.firstOrNull {
                    it.type == "DieselStoreFrontWide" || it.type == "OfferImageWide"
                }?.url ?: match.keyImages.firstOrNull {
                    it.type == "DieselGameBoxWide" || it.type == "Thumbnail"
                }?.url ?: match.keyImages.firstOrNull()?.url
            } else null
        } catch (_: Exception) {
            null
        }
    }
}

package com.example.desaappsavaloskoortuzarvargas.data.api

import kotlinx.coroutines.Dispatchers
