/**
 * Service to fetch REAL Argentine prices from the Epic Games Store.
 *
 * Uses Epic's public GraphQL API with country=AR to get the actual
 * price in ARS that an Argentine user sees on the store.
 *
 * Endpoint: https://graphql.epicgames.com/graphql
 */
class EpicPriceService {

    private val json = Json { ignoreUnknownKeys = true }

    private val searchQuery = """
        query searchStoreQuery(${'$'}country: String!, ${'$'}keywords: String!, ${'$'}count: Int) {
            Catalog {
                searchStore(
                    country: ${'$'}country,
                    keywords: ${'$'}keywords,
                    count: ${'$'}count,
                    category: "games/edition/base",
                    sortBy: "relevancy",
                    sortDir: "DESC"
                ) {
                    elements {
                        title
                        urlSlug
                        keyImages {
                            type
                            url
                        }
                        price(country: ${'$'}country) {
                            totalPrice {
                                originalPrice
                                discountPrice
                                discount
                                currencyCode
                                fmtPrice(locale: "es-AR") {
                                    originalPrice
                                    discountPrice
                                }
                            }
                        }
                        promotions {
                            promotionalOffers {
                                promotionalOffers {
                                    startDate
                                    endDate
                                }
                            }
                        }
                    }
                }
            }
        }
    """.trimIndent()

    /**
     * Search for a game on the Epic Games Store and return the Argentine price.
     * Returns null if the game is not found or an error occurs.
     */
    suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) {
        try {
            val requestBody = json.encodeToString(
                kotlinx.serialization.json.JsonObject.serializer(),
                kotlinx.serialization.json.buildJsonObject {
                    put("query", kotlinx.serialization.json.JsonPrimitive(searchQuery))
                    put("variables", kotlinx.serialization.json.buildJsonObject {
                        put("country", kotlinx.serialization.json.JsonPrimitive("AR"))
                        put("keywords", kotlinx.serialization.json.JsonPrimitive(title))
                        put("count", kotlinx.serialization.json.JsonPrimitive(3))
                    })
                }
            )

            val url = URL("https://graphql.epicgames.com/graphql")
            val conn = url.openConnection() as HttpURLConnection
            conn.requestMethod = "POST"
            conn.connectTimeout = 10000
            conn.readTimeout = 10000
            conn.setRequestProperty("Content-Type", "application/json")
            conn.setRequestProperty("Accept", "application/json")
            conn.doOutput = true
            conn.outputStream.bufferedWriter().use { it.write(requestBody) }

            if (conn.responseCode == 200) {
                val response = conn.inputStream.bufferedReader().readText()
                val parsed = json.decodeFromString<EpicGraphQLResponse>(response)
                val elements = parsed.data?.Catalog?.searchStore?.elements ?: return@withContext null

                // Only use an exact title match — do NOT fall back to first result.
                // Returning a wrong game (e.g. a Steam-exclusive) is worse than null.
                val match = elements.firstOrNull { element ->
                    element.title.equals(title, ignoreCase = true)
                } ?: return@withContext null

                val totalPrice = match.price?.totalPrice ?: return@withContext null

                // Extract a landscape image from Epic's keyImages
                val epicImageUrl = match.keyImages.firstOrNull {
                    it.type == "DieselStoreFrontWide" || it.type == "OfferImageWide"
                }?.url ?: match.keyImages.firstOrNull {
                    it.type == "DieselGameBoxWide" || it.type == "Thumbnail"
                }?.url ?: match.keyImages.firstOrNull()?.url ?: ""

                // Epic returns 0 for free games
                val isFree = totalPrice.originalPrice == 0 && totalPrice.discountPrice == 0
                val discountPct = if (totalPrice.originalPrice > 0) {
                    ((totalPrice.discount.toFloat() / totalPrice.originalPrice) * 100).toInt()
                } else 0

                // Extract promotion end date if available
                val promoEndTs = try {
                    val endDateStr = match.promotions
                        ?.promotionalOffers?.firstOrNull()
                        ?.promotionalOffers?.firstOrNull()
                        ?.endDate
                    if (!endDateStr.isNullOrEmpty()) {
                        // Epic dates are ISO 8601: "2026-06-05T15:00:00.000Z"
                        val sdf = java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'", java.util.Locale.US)
                        sdf.timeZone = java.util.TimeZone.getTimeZone("UTC")
                        sdf.parse(endDateStr)?.time
                    } else null
                } catch (_: Exception) { null }

                // Build the store URL.  Epic does NOT support es-AR in the URL path;
                // the correct format is /p/{slug} without a locale prefix.
                // If urlSlug is empty, fall back to a search page.
                val storeUrl = if (match.urlSlug.isNotEmpty()) {
                    "https://store.epicgames.com/p/${match.urlSlug}"
                } else {
                    val encoded = java.net.URLEncoder.encode(title, "UTF-8")
                    "https://store.epicgames.com/browse?q=$encoded"
                }

                StorePrice(
                    storeName = "Epic Games",
                    currentPrice = totalPrice.discountPrice / 100f,
                    originalPrice = totalPrice.originalPrice / 100f,
                    discountPercent = discountPct,
                    currency = totalPrice.currencyCode,
                    isFree = isFree,
                    storeUrl = storeUrl,
                    formattedPrice = totalPrice.fmtPrice?.discountPrice ?: "",
                    formattedOriginal = totalPrice.fmtPrice?.originalPrice ?: "",
                    imageUrl = epicImageUrl,
                    discountEndTimestamp = promoEndTs
                )
            } else null
        } catch (_: Exception) {
            null
        }
    }

    /**
     * Fetch ONLY the game image from Epic (lightweight, no price data).
     * Used at catalog load time for non-Steam games to populate their images.
     * Prefers wide/landscape images similar to Steam headers.
     */
    suspend fun fetchGameImage(title: String): String? = withContext(Dispatchers.IO) {
        try {
            val imageQuery = """
                query searchStoreQuery(${'$'}keywords: String!, ${'$'}count: Int) {
                    Catalog {
                        searchStore(
                            country: "US",
                            keywords: ${'$'}keywords,
                            count: ${'$'}count,
                            category: "games/edition/base",
                            sortBy: "relevancy",
                            sortDir: "DESC"
                        ) {
                            elements {
                                title
                                keyImages { type url }
                            }
                        }
                    }
                }
            """.trimIndent()

            val requestBody = json.encodeToString(
                kotlinx.serialization.json.JsonObject.serializer(),
                kotlinx.serialization.json.buildJsonObject {
                    put("query", kotlinx.serialization.json.JsonPrimitive(imageQuery))
                    put("variables", kotlinx.serialization.json.buildJsonObject {
                        put("keywords", kotlinx.serialization.json.JsonPrimitive(title))
                        put("count", kotlinx.serialization.json.JsonPrimitive(3))
                    })
                }
            )

            val url = URL("https://graphql.epicgames.com/graphql")
            val conn = url.openConnection() as HttpURLConnection
            conn.requestMethod = "POST"
            conn.connectTimeout = 10000
            conn.readTimeout = 10000
            conn.setRequestProperty("Content-Type", "application/json")
            conn.setRequestProperty("Accept", "application/json")
            conn.doOutput = true
            conn.outputStream.bufferedWriter().use { it.write(requestBody) }

            if (conn.responseCode == 200) {
                val response = conn.inputStream.bufferedReader().readText()
                val parsed = json.decodeFromString<EpicGraphQLResponse>(response)
                val elements = parsed.data?.Catalog?.searchStore?.elements ?: return@withContext null

                val match = elements.firstOrNull { it.title.equals(title, ignoreCase = true) }
                    ?: return@withContext null

                // Prefer wide/landscape images (like Steam headers)
                match.keyImages.firstOrNull {
                    it.type == "DieselStoreFrontWide" || it.type == "OfferImageWide"
                }?.url ?: match.keyImages.firstOrNull {
                    it.type == "DieselGameBoxWide" || it.type == "Thumbnail"
                }?.url ?: match.keyImages.firstOrNull()?.url
            } else null
        } catch (_: Exception) {
            null
        }
    }
}

package com.example.desaappsavaloskoortuzarvargas.data.api

import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import kotlinx.serialization.Serializable
import kotlinx.serialization.json.Json
import java.net.HttpURLConnection
import java.net.URL
import java.net.URLEncoder

// ── GOG Catalog API response models ──

@Serializable
data class GogCatalogResponse(
    val products: List<GogProduct> = emptyList()
)

@Serializable
data class GogProduct(
    val id: Long = 0,
    val title: String = "",
    val price: GogPriceData? = null,
    val storeLink: String = ""
)

@Serializable
data class GogPriceData(
    val amount: String = "0",
    val baseAmount: String = "0",
    val finalAmount: String = "0",
    val isDiscounted: Boolean = false,
    val discountPercentage: Int = 0,
    val currency: String = "USD",
    val isFree: Boolean = false
)

/**
 * Service to fetch REAL prices from GOG for Argentina.
 *
 * GOG uses their catalog API with countryCode parameter.
 * Note: GOG may show prices in USD for Argentina (they don't always
 * have ARS regional pricing), but the price IS what you'd actually pay.
 *
 * Endpoint: https://catalog.gog.com/v1/catalog
 */
class GogPriceService {

    private val json = Json { ignoreUnknownKeys = true }

    /**
     * Search for a game on GOG and return its Argentine price.
     * Returns null if the game is not found or an error occurs.
     */
    suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) {
        try {
            val encoded = URLEncoder.encode(title, "UTF-8")
            val url = URL(
                "https://catalog.gog.com/v1/catalog?limit=5&query=$encoded&countryCode=AR&locale=es-AR&currencyCode=ARS"
            )
            val conn = url.openConnection() as HttpURLConnection
            conn.requestMethod = "GET"
            conn.connectTimeout = 10000
            conn.readTimeout = 10000
            conn.setRequestProperty("Accept", "application/json")

            if (conn.responseCode == 200) {
                val response = conn.inputStream.bufferedReader().readText()
                val catalog = json.decodeFromString<GogCatalogResponse>(response)

                if (catalog.products.isEmpty()) return@withContext null

                // Find the best title match
                val match = catalog.products.firstOrNull { product ->
                    product.title.equals(title, ignoreCase = true)
                } ?: catalog.products.firstOrNull() ?: return@withContext null

                val priceData = match.price ?: return@withContext null

                val finalPrice = priceData.finalAmount.toFloatOrNull() ?: 0f
                val basePrice = priceData.baseAmount.toFloatOrNull() ?: finalPrice

                StorePrice(
                    storeName = "GOG",
                    currentPrice = finalPrice,
                    originalPrice = basePrice,
                    discountPercent = priceData.discountPercentage,
                    currency = priceData.currency,
                    isFree = priceData.isFree || finalPrice == 0f,
                    storeUrl = if (match.storeLink.isNotEmpty()) {
                        "https://www.gog.com${match.storeLink}"
                    } else {
                        "https://www.gog.com"
                    }
                )
            } else null
        } catch (_: Exception) {
            null
        }
    }
}

package com.example.desaappsavaloskoortuzarvargas.data.api

import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import kotlinx.serialization.Serializable
import kotlinx.serialization.json.Json
import java.net.HttpURLConnection
import java.net.URL
import java.net.URLEncoder

// ── GOG Catalog API response models ──

@Serializable
data class GogCatalogResponse(
    val products: List<GogProduct> = emptyList()
)

@Serializable
data class GogProduct(
    val id: Long = 0,
    val title: String = "",
    val slug: String = "",
    val price: GogPriceData? = null,
    val storeLink: String = ""
)

@Serializable
data class GogPriceData(
    val amount: String = "0",
    val baseAmount: String = "0",
    val finalAmount: String = "0",
    val isDiscounted: Boolean = false,
    val discountPercentage: Int = 0,
    val currency: String = "USD",
    val isFree: Boolean = false
)

/**
 * Service to fetch REAL prices from GOG for Argentina.
 *
 * GOG uses their catalog API with countryCode parameter.
 * Note: GOG may show prices in USD for Argentina (they don't always
 * have ARS regional pricing), but the price IS what you'd actually pay.
 *
 * Endpoint: https://catalog.gog.com/v1/catalog
 */
class GogPriceService {

    private val json = Json { ignoreUnknownKeys = true }

    /**
     * Search for a game on GOG and return its Argentine price.
     * Returns null if the game is not found or an error occurs.
     */
    suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) {
        try {
            val encoded = URLEncoder.encode(title, "UTF-8")
            val url = URL(
                "https://catalog.gog.com/v1/catalog?limit=5&query=$encoded&countryCode=AR&locale=es-AR&currencyCode=USD"
            )
            val conn = url.openConnection() as HttpURLConnection
            conn.requestMethod = "GET"
            conn.connectTimeout = 10000
            conn.readTimeout = 10000
            conn.setRequestProperty("Accept", "application/json")

            if (conn.responseCode == 200) {
                val response = conn.inputStream.bufferedReader().readText()
                val catalog = json.decodeFromString<GogCatalogResponse>(response)

                if (catalog.products.isEmpty()) return@withContext null

                // Only use an exact title match — do NOT fall back to first result.
                // Returning a wrong game is worse than returning null.
                val match = catalog.products.firstOrNull { product ->
                    product.title.equals(title, ignoreCase = true)
                } ?: return@withContext null

                val priceData = match.price ?: return@withContext null

                val finalPrice = priceData.finalAmount.toFloatOrNull() ?: 0f
                val basePrice = priceData.baseAmount.toFloatOrNull() ?: finalPrice

                // If the API returns 0 and the game is NOT explicitly marked as free,
                // it means GOG doesn't have ARS regional pricing — skip to avoid showing
                // a paid game as "FREE".
                if (finalPrice == 0f && !priceData.isFree) return@withContext null

                // Build the store URL.  GOG's API returns a `slug` field (e.g. "what_remains_of_edith_finch").
                // The product page is at gog.com/game/{slug}.
                // storeLink (if present) is a relative path like "/game/slug" – preferred when available.
                // Fallback: title search so the user at least lands near the game.
                val storeUrl = when {
                    match.storeLink.isNotEmpty() -> {
                        val link = if (match.storeLink.startsWith("/")) match.storeLink else "/${match.storeLink}"
                        "https://www.gog.com$link"
                    }
                    match.slug.isNotEmpty() -> "https://www.gog.com/game/${match.slug}"
                    else -> {
                        val encoded = URLEncoder.encode(title, "UTF-8")
                        "https://www.gog.com/games?search=$encoded"
                    }
                }

                StorePrice(
                    storeName = "GOG",
                    currentPrice = finalPrice,
                    originalPrice = basePrice,
                    discountPercent = priceData.discountPercentage,
                    currency = priceData.currency,
                    isFree = priceData.isFree,
                    storeUrl = storeUrl
                )
            } else null
        } catch (_: Exception) {
            null
        }
    }
}

package com.example.desaappsavaloskoortuzarvargas.data.api

import com.example.desaappsavaloskoortuzarvargas.data.local.ConnectivityObserver
import com.example.desaappsavaloskoortuzarvargas.data.local.dao.GamePriceDao
import com.example.desaappsavaloskoortuzarvargas.data.local.dao.PriceHistoryDao
import com.example.desaappsavaloskoortuzarvargas.data.local.entity.GamePriceEntity
import com.example.desaappsavaloskoortuzarvargas.data.local.entity.PriceHistoryEntity
import kotlinx.coroutines.CancellationException
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.Job
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.async
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch

/**
 * Manages background price refreshing with batching and staleness logic.
 *
 * Strategy:
 * - **On game detail open**: Show cached prices instantly, then refresh from APIs
 *   in the background. Only hit the network if cache is older than [DETAIL_STALE_MS].
 * - **Offers section** (high priority): Refresh stale offer prices every
 *   [OFFERS_REFRESH_INTERVAL_MS] in batches of [BATCH_SIZE] with [BATCH_DELAY_MS]
 *   between batches.
 * - **General catalog**: Refresh in the background every [CATALOG_REFRESH_INTERVAL_MS],
 *   processing the oldest-cached games first, in batches.
 *
 * All network calls go through the individual store services (Steam, Epic, GOG, etc.).
 * This class coordinates WHEN and HOW MANY calls to make, not WHERE to call.
 */
class PriceRefreshManager(
    private val gamePriceDao: GamePriceDao,
    private val priceHistoryDao: PriceHistoryDao,
    private val steamPriceService: SteamPriceService,
    private val epicPriceService: EpicPriceService,
    private val gogPriceService: GogPriceService,
    private val xboxPriceService: XboxPriceService,
    private val ubisoftPriceService: UbisoftPriceService,
    private val battleNetPriceService: BattleNetPriceService,
    private val eaPriceService: EAPriceService,
    private val connectivityObserver: ConnectivityObserver
) {
    companion object {
        /** Cache is "stale" for individual game detail after 10 minutes. */
        const val DETAIL_STALE_MS = 10 * 60 * 1000L   // 10 min

        /** Offers refresh cycle: every 30 minutes. */
        const val OFFERS_REFRESH_INTERVAL_MS = 30 * 60 * 1000L  // 30 min

        /** General catalog refresh cycle: every 2 hours. */
        const val CATALOG_REFRESH_INTERVAL_MS = 2 * 60 * 60 * 1000L  // 2 h

        /** Number of games to refresh per batch. */
        const val BATCH_SIZE = 5

        /** Delay between batches to avoid overwhelming APIs. */
        const val BATCH_DELAY_MS = 3_000L  // 3 seconds

        /** Delay between individual game fetches within a batch. */
        const val INTRA_BATCH_DELAY_MS = 500L  // 500ms
    }

    private val scope = CoroutineScope(SupervisorJob() + Dispatchers.IO)
    private var offersRefreshJob: Job? = null
    private var catalogRefreshJob: Job? = null

    // Steam App IDs for quick lookup (populated from GameCatalog)
    private var steamAppIdMap: Map<String, Int> = emptyMap()

    /**
     * Set the mapping from game name → Steam App ID.
     * Called once when the game catalog is loaded.
     */
    fun setSteamAppIds(map: Map<String, Int>) {
        steamAppIdMap = map
    }

    // ──────────────────────────────────────────────────────────────
    //  Single-game refresh (used when user opens a game detail)
    // ──────────────────────────────────────────────────────────────

    /**
     * Check if cached prices for [gameName] are fresh enough.
     * Returns true if prices exist and are newer than [maxAge].
     */
    suspend fun isCacheFresh(gameName: String, maxAge: Long = DETAIL_STALE_MS): Boolean {
        val oldest = gamePriceDao.getOldestTimestamp(gameName) ?: return false
        return (System.currentTimeMillis() - oldest) < maxAge
    }

    /**
     * Get cached prices for a game. Returns empty list if none cached.
     */
    suspend fun getCachedPrices(gameName: String): List<StorePrice> {
        return gamePriceDao.getPricesForGameByName(gameName).map { it.toStorePrice() }
    }

    /**
     * Get ALL cached prices from the database (all games, all stores).
     */
    suspend fun getAllCachedPrices(): List<GamePriceEntity> {
        return gamePriceDao.getAllPrices()
    }

    /**
     * Check if the current price for a game/store is the all-time historical low.
     */
    suspend fun isHistoricalLow(gameName: String, storeName: String, currentPrice: Float): Boolean {
        if (currentPrice <= 0f) return false
        val historicalLow = priceHistoryDao.getHistoricalLowPrice(gameName, storeName)
        return historicalLow == null || currentPrice <= historicalLow
    }

    /**
     * Detect a permanent base price drop: when the publisher reduced the non-discounted price.
     * Returns the previous retail price if a drop is detected, null otherwise.
     */
    suspend fun detectPriceDrop(gameName: String, storeName: String, currentRetailPrice: Float): Float? {
        if (currentRetailPrice <= 0f) return null
        val previousRetail = priceHistoryDao.getPreviousRetailPrice(gameName, storeName) ?: return null
        // Require at least 10% drop to consider it a "permanent price drop"
        return if (currentRetailPrice < previousRetail * 0.9f) previousRetail else null
    }

    /**
     * Fetch fresh prices for a single game from all stores.
     * Saves to cache. Returns the fetched prices.
     */
    suspend fun fetchAndCachePrices(
        gameName: String,
        steamAppId: Int? = null
    ): List<StorePrice> {
        if (!(connectivityObserver.isConnected())) return emptyList()

        val prices = fetchAllStorePrices(gameName, steamAppId)
        if (prices.isNotEmpty()) {
            savePricesToCache(gameName, prices)
        }
        return prices
    }

    // ──────────────────────────────────────────────────────────────
    //  Background batch refresh
    // ──────────────────────────────────────────────────────────────

    /**
     * Start the periodic background refresh for offers and catalog.
     * Call once from the main activity / app initialization.
     */
    fun startPeriodicRefresh() {
        startOffersRefreshLoop()
        startCatalogRefreshLoop()
    }

    /**
     * Stop all background refresh jobs.
     */
    fun stopPeriodicRefresh() {
        offersRefreshJob?.cancel()
        catalogRefreshJob?.cancel()
    }

    /**
     * Refresh a specific list of game names (e.g., games shown in offers).
     * Processes in batches of [BATCH_SIZE].
     *
     * @param onBatchComplete Called after each batch so the UI can update progressively.
     */
    suspend fun refreshBatch(
        gameNames: List<String>,
        onBatchComplete: (suspend () -> Unit)? = null
    ) {
        if (!(connectivityObserver.isConnected())) return

        val batches = gameNames.chunked(BATCH_SIZE)
        for (batch in batches) {
            for (gameName in batch) {
                try {
                    val steamAppId = steamAppIdMap[gameName]
                    fetchAndCachePrices(gameName, steamAppId)
                } catch (e: CancellationException) { throw e }
                catch (_: Exception) { /* skip failed game, continue batch */ }
                delay(INTRA_BATCH_DELAY_MS)
            }
            // Notify after each batch so UI can refresh with new data
            onBatchComplete?.invoke()
            if (batch != batches.last()) {
                delay(BATCH_DELAY_MS)
            }
        }
    }

    /**
     * Refresh the stalest cached games. Called periodically for
     * general catalog freshness.
     */
    suspend fun refreshStalestGames(maxGames: Int = BATCH_SIZE * 3) {
        if (!(connectivityObserver.isConnected())) return

        val staleThreshold = System.currentTimeMillis() - CATALOG_REFRESH_INTERVAL_MS
        val staleNames = gamePriceDao.getStaleGameNames(staleThreshold)
            .take(maxGames)

        if (staleNames.isNotEmpty()) {
            refreshBatch(staleNames)
        }
    }

    /**
     * Ensure all catalog games have been fetched at least once.
     * Games that already have cached prices are skipped.
     * Called on app startup to populate the offers section.
     *
     * @param onBatchComplete Called after each batch finishes so the UI
     *        can refresh progressively instead of waiting for all games.
     */
    suspend fun ensureAllGamesCached(
        allGameNames: List<String>,
        onBatchComplete: (suspend () -> Unit)? = null
    ) {
        if (!(connectivityObserver.isConnected())) return

        val cachedNames = gamePriceDao.getAllCachedGameNamesOldestFirst().toSet()
        val uncached = allGameNames.filter { it !in cachedNames }

        if (uncached.isNotEmpty()) {
            refreshBatch(uncached, onBatchComplete)
        }
    }

    // ──────────────────────────────────────────────────────────────
    //  Private helpers
    // ──────────────────────────────────────────────────────────────

    private fun startOffersRefreshLoop() {
        offersRefreshJob?.cancel()
        offersRefreshJob = scope.launch {
            while (true) {
                delay(OFFERS_REFRESH_INTERVAL_MS)
                try {
                    // Refresh all cached games — offers are most important
                    val staleThreshold = System.currentTimeMillis() - OFFERS_REFRESH_INTERVAL_MS
                    val stale = gamePriceDao.getStaleGameNames(staleThreshold)
                    if (stale.isNotEmpty()) {
                        refreshBatch(stale)
                    }
                } catch (e: CancellationException) { throw e }
                catch (_: Exception) { }
            }
        }
    }

    private fun startCatalogRefreshLoop() {
        catalogRefreshJob?.cancel()
        catalogRefreshJob = scope.launch {
            // Initial delay — let the app start up first
            delay(60_000)
            while (true) {
                try {
                    refreshStalestGames()
                } catch (e: CancellationException) { throw e }
                catch (_: Exception) { }
                delay(CATALOG_REFRESH_INTERVAL_MS)
            }
        }
    }

    /**
     * Fetch prices from all 7 stores in parallel for a single game.
     */
    private suspend fun fetchAllStorePrices(
        gameName: String,
        steamAppId: Int? = null
    ): List<StorePrice> = kotlinx.coroutines.coroutineScope {
        val prices = mutableListOf<StorePrice>()

        val steamJob = async {
            if (steamAppId != null && steamAppId > 0) {
                try {
                    steamPriceService.getArgentinePrice(steamAppId)?.let { arPrice ->
                        StorePrice(
                            storeName = "Steam",
                            currentPrice = arPrice.price,
                            originalPrice = arPrice.retailPrice,
                            discountPercent = arPrice.discountPercent,
                            currency = arPrice.currency,
                            isFree = arPrice.isFree,
                            storeUrl = "https://store.steampowered.com/app/$steamAppId",
                            discountEndTimestamp = arPrice.discountEndTimestamp
                        )
                    }
                } catch (_: Exception) { null }
            } else null
        }

        val epicJob = async {
            try { epicPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        val gogJob = async {
            try { gogPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        val xboxJob = async {
            try { xboxPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        val ubisoftJob = async {
            try { ubisoftPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        val battleNetJob = async {
            try { battleNetPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        val eaJob = async {
            try { eaPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        steamJob.await()?.let { prices.add(it) }
        epicJob.await()?.let { prices.add(it) }
        gogJob.await()?.let { prices.add(it) }
        xboxJob.await()?.let { prices.add(it) }
        ubisoftJob.await()?.let { prices.add(it) }
        battleNetJob.await()?.let { prices.add(it) }
        eaJob.await()?.let { prices.add(it) }

        prices
    }

    private suspend fun savePricesToCache(gameName: String, prices: List<StorePrice>) {
        try {
            gamePriceDao.deletePricesForGameByName(gameName)
            gamePriceDao.insertAll(prices.map { price ->
                GamePriceEntity(
                    gameId = 0,
                    gameName = gameName,
                    storeName = price.storeName,
                    currentPrice = price.currentPrice,
                    retailPrice = price.originalPrice,
                    savings = price.discountPercent.toFloat(),
                    dealUrl = price.storeUrl,
                    currency = price.currency,
                    discountEndTimestamp = price.discountEndTimestamp
                )
            })
            // Record price history snapshot for historical tracking
            val now = System.currentTimeMillis()
            priceHistoryDao.insertAll(prices.map { price ->
                PriceHistoryEntity(
                    gameName = gameName,
                    storeName = price.storeName,
                    currentPrice = price.currentPrice,
                    retailPrice = price.originalPrice,
                    discountPercent = price.discountPercent,
                    currency = price.currency,
                    timestamp = now
                )
            })
        } catch (_: Exception) { }
    }

    private fun GamePriceEntity.toStorePrice() = StorePrice(
        storeName = storeName,
        currentPrice = currentPrice,
        originalPrice = retailPrice,
        discountPercent = savings.toInt(),
        currency = currency,
        isFree = currentPrice == 0f,
        storeUrl = dealUrl,
        discountEndTimestamp = discountEndTimestamp
    )
}

package com.example.desaappsavaloskoortuzarvargas.data.api

import com.example.desaappsavaloskoortuzarvargas.data.local.ConnectivityObserver
import com.example.desaappsavaloskoortuzarvargas.data.local.dao.GamePriceDao
import com.example.desaappsavaloskoortuzarvargas.data.local.dao.PriceHistoryDao
import com.example.desaappsavaloskoortuzarvargas.data.local.entity.GamePriceEntity
import com.example.desaappsavaloskoortuzarvargas.data.local.entity.PriceHistoryEntity
import kotlinx.coroutines.CancellationException
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.Job
import kotlinx.coroutines.SupervisorJob
import kotlinx.coroutines.async
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch

/**
 * Manages background price refreshing with batching and staleness logic.
 *
 * Strategy:
 * - **On game detail open**: Show cached prices instantly, then refresh from APIs
 *   in the background. Only hit the network if cache is older than [DETAIL_STALE_MS].
 * - **Offers section** (high priority): Refresh stale offer prices every
 *   [OFFERS_REFRESH_INTERVAL_MS] in batches of [BATCH_SIZE] with [BATCH_DELAY_MS]
 *   between batches.
 * - **General catalog**: Refresh in the background every [CATALOG_REFRESH_INTERVAL_MS],
 *   processing the oldest-cached games first, in batches.
 *
 * All network calls go through the individual store services (Steam, Epic, GOG, etc.).
 * This class coordinates WHEN and HOW MANY calls to make, not WHERE to call.
 */
class PriceRefreshManager(
    private val gamePriceDao: GamePriceDao,
    private val priceHistoryDao: PriceHistoryDao,
    private val steamPriceService: SteamPriceService,
    private val epicPriceService: EpicPriceService,
    private val gogPriceService: GogPriceService,
    private val xboxPriceService: XboxPriceService,
    private val ubisoftPriceService: UbisoftPriceService,
    private val battleNetPriceService: BattleNetPriceService,
    private val eaPriceService: EAPriceService,
    private val connectivityObserver: ConnectivityObserver
) {
    companion object {
        /** Cache is "stale" for individual game detail after 5 minutes. */
        const val DETAIL_STALE_MS = 5 * 60 * 1000L    // 5 min

        /** Offers refresh cycle: every 15 minutes. */
        const val OFFERS_REFRESH_INTERVAL_MS = 15 * 60 * 1000L  // 15 min

        /** General catalog refresh cycle: every 1 hour. */
        const val CATALOG_REFRESH_INTERVAL_MS = 60 * 60 * 1000L  // 1 h

        /** Number of games to refresh per batch. */
        const val BATCH_SIZE = 5

        /** Delay between batches to avoid overwhelming APIs. */
        const val BATCH_DELAY_MS = 3_000L  // 3 seconds

        /** Delay between individual game fetches within a batch. */
        const val INTRA_BATCH_DELAY_MS = 500L  // 500ms
    }

    private val scope = CoroutineScope(SupervisorJob() + Dispatchers.IO)
    private var offersRefreshJob: Job? = null
    private var catalogRefreshJob: Job? = null

    // Steam App IDs for quick lookup (populated from GameCatalog)
    private var steamAppIdMap: Map<String, Int> = emptyMap()

    /**
     * Set the mapping from game name → Steam App ID.
     * Called once when the game catalog is loaded.
     */
    fun setSteamAppIds(map: Map<String, Int>) {
        steamAppIdMap = map
    }

    // ──────────────────────────────────────────────────────────────
    //  Single-game refresh (used when user opens a game detail)
    // ──────────────────────────────────────────────────────────────

    /**
     * Check if cached prices for [gameName] are fresh enough.
     * Returns true if prices exist and are newer than [maxAge].
     */
    suspend fun isCacheFresh(gameName: String, maxAge: Long = DETAIL_STALE_MS): Boolean {
        val oldest = gamePriceDao.getOldestTimestamp(gameName) ?: return false
        return (System.currentTimeMillis() - oldest) < maxAge
    }

    /**
     * Get cached prices for a game. Returns empty list if none cached.
     */
    suspend fun getCachedPrices(gameName: String): List<StorePrice> {
        return gamePriceDao.getPricesForGameByName(gameName).map { it.toStorePrice() }
    }

    /**
     * Get ALL cached prices from the database (all games, all stores).
     */
    suspend fun getAllCachedPrices(): List<GamePriceEntity> {
        return gamePriceDao.getAllPrices()
    }

    /**
     * Check if the current price for a game/store is the all-time historical low.
     */
    suspend fun isHistoricalLow(gameName: String, storeName: String, currentPrice: Float): Boolean {
        if (currentPrice <= 0f) return false
        val historicalLow = priceHistoryDao.getHistoricalLowPrice(gameName, storeName)
        return historicalLow == null || currentPrice <= historicalLow
    }

    /**
     * Detect a permanent base price drop: when the publisher reduced the non-discounted price.
     * Returns the previous retail price if a drop is detected, null otherwise.
     */
    suspend fun detectPriceDrop(gameName: String, storeName: String, currentRetailPrice: Float): Float? {
        if (currentRetailPrice <= 0f) return null
        val previousRetail = priceHistoryDao.getPreviousRetailPrice(gameName, storeName) ?: return null
        // Require at least 10% drop to consider it a "permanent price drop"
        return if (currentRetailPrice < previousRetail * 0.9f) previousRetail else null
    }

    /**
     * Fetch fresh prices for a single game from all stores.
     * Saves to cache. Returns the fetched prices.
     */
    suspend fun fetchAndCachePrices(
        gameName: String,
        steamAppId: Int? = null
    ): List<StorePrice> {
        if (!(connectivityObserver.isConnected())) return emptyList()

        val prices = fetchAllStorePrices(gameName, steamAppId)
        if (prices.isNotEmpty()) {
            savePricesToCache(gameName, prices)
        }
        return prices
    }

    // ──────────────────────────────────────────────────────────────
    //  Background batch refresh
    // ──────────────────────────────────────────────────────────────

    /**
     * Start the periodic background refresh for offers and catalog.
     * Call once from the main activity / app initialization.
     */
    fun startPeriodicRefresh() {
        startOffersRefreshLoop()
        startCatalogRefreshLoop()
    }

    /**
     * Stop all background refresh jobs.
     */
    fun stopPeriodicRefresh() {
        offersRefreshJob?.cancel()
        catalogRefreshJob?.cancel()
    }

    /**
     * Refresh a specific list of game names (e.g., games shown in offers).
     * Processes in batches of [BATCH_SIZE].
     *
     * @param onBatchComplete Called after each batch so the UI can update progressively.
     */
    suspend fun refreshBatch(
        gameNames: List<String>,
        onBatchComplete: (suspend () -> Unit)? = null
    ) {
        if (!(connectivityObserver.isConnected())) return

        val batches = gameNames.chunked(BATCH_SIZE)
        for (batch in batches) {
            for (gameName in batch) {
                try {
                    val steamAppId = steamAppIdMap[gameName]
                    fetchAndCachePrices(gameName, steamAppId)
                } catch (e: CancellationException) { throw e }
                catch (_: Exception) { /* skip failed game, continue batch */ }
                delay(INTRA_BATCH_DELAY_MS)
            }
            // Notify after each batch so UI can refresh with new data
            onBatchComplete?.invoke()
            if (batch != batches.last()) {
                delay(BATCH_DELAY_MS)
            }
        }
    }

    /**
     * Refresh the stalest cached games. Called periodically for
     * general catalog freshness.
     */
    suspend fun refreshStalestGames(maxGames: Int = BATCH_SIZE * 3) {
        if (!(connectivityObserver.isConnected())) return

        val staleThreshold = System.currentTimeMillis() - CATALOG_REFRESH_INTERVAL_MS
        val staleNames = gamePriceDao.getStaleGameNames(staleThreshold)
            .take(maxGames)

        if (staleNames.isNotEmpty()) {
            refreshBatch(staleNames)
        }
    }

    /**
     * Ensure all catalog games have been fetched at least once.
     * Games that already have cached prices are skipped.
     * Called on app startup to populate the offers section.
     *
     * @param onBatchComplete Called after each batch finishes so the UI
     *        can refresh progressively instead of waiting for all games.
     */
    suspend fun ensureAllGamesCached(
        allGameNames: List<String>,
        onBatchComplete: (suspend () -> Unit)? = null
    ) {
        if (!(connectivityObserver.isConnected())) return

        val cachedNames = gamePriceDao.getAllCachedGameNamesOldestFirst().toSet()
        val uncached = allGameNames.filter { it !in cachedNames }

        if (uncached.isNotEmpty()) {
            refreshBatch(uncached, onBatchComplete)
        }
    }

    // ──────────────────────────────────────────────────────────────
    //  Private helpers
    // ──────────────────────────────────────────────────────────────

    private fun startOffersRefreshLoop() {
        offersRefreshJob?.cancel()
        offersRefreshJob = scope.launch {
            while (true) {
                delay(OFFERS_REFRESH_INTERVAL_MS)
                try {
                    // Refresh all cached games — offers are most important
                    val staleThreshold = System.currentTimeMillis() - OFFERS_REFRESH_INTERVAL_MS
                    val stale = gamePriceDao.getStaleGameNames(staleThreshold)
                    if (stale.isNotEmpty()) {
                        refreshBatch(stale)
                    }
                } catch (e: CancellationException) { throw e }
                catch (_: Exception) { }
            }
        }
    }

    private fun startCatalogRefreshLoop() {
        catalogRefreshJob?.cancel()
        catalogRefreshJob = scope.launch {
            // Initial delay — let the app start up first
            delay(60_000)
            while (true) {
                try {
                    refreshStalestGames()
                } catch (e: CancellationException) { throw e }
                catch (_: Exception) { }
                delay(CATALOG_REFRESH_INTERVAL_MS)
            }
        }
    }

    /**
     * Fetch prices from all 7 stores in parallel for a single game.
     */
    private suspend fun fetchAllStorePrices(
        gameName: String,
        steamAppId: Int? = null
    ): List<StorePrice> = kotlinx.coroutines.coroutineScope {
        val prices = mutableListOf<StorePrice>()

        val steamJob = async {
            if (steamAppId != null && steamAppId > 0) {
                try {
                    steamPriceService.getArgentinePrice(steamAppId)?.let { arPrice ->
                        StorePrice(
                            storeName = "Steam",
                            currentPrice = arPrice.price,
                            originalPrice = arPrice.retailPrice,
                            discountPercent = arPrice.discountPercent,
                            currency = arPrice.currency,
                            isFree = arPrice.isFree,
                            storeUrl = "https://store.steampowered.com/app/$steamAppId",
                            discountEndTimestamp = arPrice.discountEndTimestamp
                        )
                    }
                } catch (_: Exception) { null }
            } else null
        }

        val epicJob = async {
            try { epicPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        val gogJob = async {
            try { gogPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        val xboxJob = async {
            try { xboxPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        val ubisoftJob = async {
            try { ubisoftPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        val battleNetJob = async {
            try { battleNetPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        val eaJob = async {
            try { eaPriceService.searchGamePrice(gameName) } catch (_: Exception) { null }
        }

        steamJob.await()?.let { prices.add(it) }
        epicJob.await()?.let { prices.add(it) }
        gogJob.await()?.let { prices.add(it) }
        xboxJob.await()?.let { prices.add(it) }
        ubisoftJob.await()?.let { prices.add(it) }
        battleNetJob.await()?.let { prices.add(it) }
        eaJob.await()?.let { prices.add(it) }

        prices
    }

    private suspend fun savePricesToCache(gameName: String, prices: List<StorePrice>) {
        try {
            gamePriceDao.deletePricesForGameByName(gameName)
            gamePriceDao.insertAll(prices.map { price ->
                GamePriceEntity(
                    gameId = 0,
                    gameName = gameName,
                    storeName = price.storeName,
                    currentPrice = price.currentPrice,
                    retailPrice = price.originalPrice,
                    savings = price.discountPercent.toFloat(),
                    dealUrl = price.storeUrl,
                    currency = price.currency,
                    discountEndTimestamp = price.discountEndTimestamp
                )
            })
            // Record price history snapshot for historical tracking
            val now = System.currentTimeMillis()
            priceHistoryDao.insertAll(prices.map { price ->
                PriceHistoryEntity(
                    gameName = gameName,
                    storeName = price.storeName,
                    currentPrice = price.currentPrice,
                    retailPrice = price.originalPrice,
                    discountPercent = price.discountPercent,
                    currency = price.currency,
                    timestamp = now
                )
            })
        } catch (_: Exception) { }
    }

    private fun GamePriceEntity.toStorePrice() = StorePrice(
        storeName = storeName,
        currentPrice = currentPrice,
        originalPrice = retailPrice,
        discountPercent = savings.toInt(),
        currency = currency,
        isFree = currentPrice == 0f,
        storeUrl = dealUrl,
        discountEndTimestamp = discountEndTimestamp
    )
}

package com.example.desaappsavaloskoortuzarvargas.data.api
import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.withContext import kotlinx.serialization.Serializable import kotlinx.serialization.json.Json import kotlinx.serialization.json.jsonObject import kotlinx.serialization.json.jsonArray import kotlinx.serialization.json.jsonPrimitive import kotlinx.serialization.json.longOrNull import java.net.HttpURLConnection import java.net.URL
/** * Represents a single news item from the Steam News API. * These are real announcements published by game developers on the Steam store page. */ data class SteamNewsItem( val gid: String, val title: String, val url: String, val author: String, val contents: String, val date: Long, // Unix timestamp (seconds) val feedname: String, val appId: Int ) { /** ISO date string (YYYY-MM-DD) derived from the Unix timestamp. */ val dateFormatted: String get() { val sdf = java.text.SimpleDateFormat("yyyy-MM-dd", java.util.Locale.US) return sdf.format(java.util.Date(date * 1000L)) }
/** * Guess the news category based on keywords in the title. */ val category: String get() = when { title.contains(Regex("(?i)sale|discount|deal|off|free|gratis|oferta|descuento")) -> "discount" title.contains(Regex("(?i)dlc|expansion|content|pack|pass|season|update|patch|fix|hotfix|actualiz")) -> "update" title.contains(Regex("(?i)event|tournament|league|season|challenge|contest|community")) -> "event" title.contains(Regex("(?i)launch|release|now available|out now|lanzamiento|disponible")) -> "release" else -> "update" } }
/** * Service to fetch real developer news from the Steam News API. * * Endpoint: https://api.steampowered.com/ISteamNews/GetNewsForApp/v2/ * No API key required. Returns news in the `appnews.newsitems` array. * * Content is filtered to `steam_community_announcements` feed so only * developer-posted announcements are returned (not reviews or third-party articles). */ class SteamNewsService {
private val json = Json { ignoreUnknownKeys = true; isLenient = true }
/** In-memory cache: appId → (items, fetchTimestampMs) */ private val cache = mutableMapOf<Int, Pair<List<SteamNewsItem>, Long>>() private val CACHE_TTL_MS = 20 * 60 * 1000L // 20 minutes
/** * Fetch the latest developer announcements for a Steam app. * Results are cached for [CACHE_TTL_MS] milliseconds. * * @param appId Steam application ID * @param count Maximum number of items to return (default 5) * @return List of [SteamNewsItem], or null if the request failed */ suspend fun getNewsForApp(appId: Int, count: Int = 5): List<SteamNewsItem>? = withContext(Dispatchers.IO) { val now = System.currentTimeMillis() val cached = cache[appId] if (cached != null && now - cached.second < CACHE_TTL_MS) { return@withContext cached.first }
try { val urlStr = "https://api.steampowered.com/ISteamNews/GetNewsForApp/v2/" + "?appid=$appId&count=$count&maxlength=1200&format=json" + "&feeds=steam_community_announcements" val url = URL(urlStr) val conn = url.openConnection() as HttpURLConnection conn.requestMethod = "GET" conn.connectTimeout = 8000 conn.readTimeout = 8000 conn.setRequestProperty("Accept", "application/json")
if (conn.responseCode != 200) return@withContext null
val body = conn.inputStream.bufferedReader().readText() val root = json.parseToJsonElement(body).jsonObject val appNews = root["appnews"]?.jsonObject ?: return@withContext null val items = appNews["newsitems"]?.jsonArray ?: return@withContext null
val newsItems = items.mapNotNull { element -> try { val obj = element.jsonObject val gid = obj["gid"]?.jsonPrimitive?.content ?: "" val title = obj["title"]?.jsonPrimitive?.content ?: return@mapNotNull null val itemUrl = obj["url"]?.jsonPrimitive?.content ?: "" val author = obj["author"]?.jsonPrimitive?.content ?: "" val rawContents = obj["contents"]?.jsonPrimitive?.content ?: "" val date = obj["date"]?.jsonPrimitive?.longOrNull ?: 0L val feedname = obj["feedname"]?.jsonPrimitive?.content ?: "" val itemAppId = obj["appid"]?.jsonPrimitive?.longOrNull?.toInt() ?: appId
SteamNewsItem( gid = gid, title = title, url = itemUrl, author = author, contents = stripMarkup(rawContents), date = date, feedname = feedname, appId = itemAppId ) } catch (_: Exception) { null } }
cache[appId] = Pair(newsItems, now) newsItems } catch (_: Exception) { null } }
/** * Strip Steam-flavored BBCode and HTML markup from news content * so it displays as clean plain text. */ private fun stripMarkup(raw: String): String { return raw .replace(Regex("\\[img\\][^\\[]*\\[/img\\]", RegexOption.IGNORE_CASE), "") .replace(Regex("\\[url=[^]]*\\]([^\\[]*)\\[/url\\]", RegexOption.IGNORE_CASE), "$1") .replace(Regex("\\[/?(b|i|u|h[1-6]|list|\\*|quote|code|strike|spoiler|previewyoutube)[^]]*\\]", RegexOption.IGNORE_CASE), "") .replace(Regex("<[^>]+>"), "") .replace(Regex("&amp;"), "&") .replace(Regex("&lt;"), "<") .replace(Regex("&gt;"), ">") .replace(Regex("&quot;"), "\"") .replace(Regex("\\{STEAM_CLAN_IMAGE}[^ \\n]*"), "") .replace(Regex("\n{3,}"), "\n\n") .trim() } }

package com.example.desaappsavaloskoortuzarvargas.data.api
import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.withContext import kotlinx.serialization.json.Json import kotlinx.serialization.json.JsonObject import kotlinx.serialization.json.jsonArray import kotlinx.serialization.json.jsonObject import kotlinx.serialization.json.jsonPrimitive import java.net.HttpURLConnection import java.net.URL import java.net.URLEncoder
/** * Service to fetch prices from the Ubisoft Connect Store for Argentina. * * Ubisoft's store API is not officially public, but their storefront * uses accessible JSON endpoints. We try the Ubisoft Store API with * Argentine locale. If it fails, returns null gracefully. * * Note: Most Ubisoft games are also available on Steam and Epic Games, * so those services will typically cover Ubisoft titles too. */ class UbisoftPriceService {
private val json = Json { ignoreUnknownKeys = true }
/** * Search for a game on the Ubisoft Store and return the Argentine price. * Uses Ubisoft's internal store API with AR locale. */ suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) { try { val encoded = URLEncoder.encode(title, "UTF-8") // Ubisoft's storefront search API (Demandware-based) val url = URL( "https://store.ubisoft.com/on/demandware.store/Sites-us-ubisoft-Site/es_AR/" + "Search-GetSuggestions?q=$encoded" ) val conn = url.openConnection() as HttpURLConnection conn.requestMethod = "GET" conn.connectTimeout = 8000 conn.readTimeout = 8000 conn.setRequestProperty("Accept", "application/json") conn.setRequestProperty("User-Agent", "Mozilla/5.0")
if (conn.responseCode == 200) { val response = conn.inputStream.bufferedReader().readText() val parsed = json.decodeFromString<JsonObject>(response)
// Try to extract product info from the suggestions response val products = parsed["products"]?.jsonObject?.get("hits")?.jsonArray ?: return@withContext null
if (products.isEmpty()) return@withContext null
val firstHit = products[0].jsonObject val productTitle = firstHit["title"]?.jsonPrimitive?.content ?: title val priceValue = firstHit["price"]?.jsonObject val currentPrice = priceValue?.get("sales")?.jsonObject?.get("value") ?.jsonPrimitive?.content?.toFloatOrNull() val originalPrice = priceValue?.get("list")?.jsonObject?.get("value") ?.jsonPrimitive?.content?.toFloatOrNull() val currency = priceValue?.get("sales")?.jsonObject?.get("currency") ?.jsonPrimitive?.content ?: "USD" val productUrl = firstHit["url"]?.jsonPrimitive?.content ?: ""
if (currentPrice == null) return@withContext null
val msrp = originalPrice ?: currentPrice val discountPct = if (msrp > 0 && currentPrice < msrp) { ((1 - currentPrice / msrp) * 100).toInt() } else 0
StorePrice( storeName = "Ubisoft", currentPrice = currentPrice, originalPrice = msrp, discountPercent = discountPct, currency = currency, isFree = currentPrice == 0f, storeUrl = if (productUrl.isNotEmpty()) { "https://store.ubisoft.com$productUrl" } else "https://store.ubisoft.com" ) } else null } catch (_: Exception) { null } } }

package com.example.desaappsavaloskoortuzarvargas.data.api
import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.withContext import kotlinx.serialization.json.Json import kotlinx.serialization.json.JsonObject import kotlinx.serialization.json.jsonArray import kotlinx.serialization.json.jsonObject import kotlinx.serialization.json.jsonPrimitive import java.net.HttpURLConnection import java.net.URL import java.net.URLEncoder
/** * Service to fetch prices from the Ubisoft Connect Store for Argentina. * * Ubisoft's store API is not officially public, but their storefront * uses accessible JSON endpoints. We try the Ubisoft Store API with * Argentine locale. If it fails, returns null gracefully. * * Note: Most Ubisoft games are also available on Steam and Epic Games, * so those services will typically cover Ubisoft titles too. */ class UbisoftPriceService {
private val json = Json { ignoreUnknownKeys = true }
/** * Search for a game on the Ubisoft Store and return the Argentine price. * Uses Ubisoft's internal store API with AR locale. */ suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) { try { val encoded = URLEncoder.encode(title, "UTF-8") // Ubisoft's storefront search API (Demandware-based) val url = URL( "https://store.ubisoft.com/on/demandware.store/Sites-us-ubisoft-Site/es_AR/" + "Search-GetSuggestions?q=$encoded" ) val conn = url.openConnection() as HttpURLConnection conn.requestMethod = "GET" conn.connectTimeout = 8000 conn.readTimeout = 8000 conn.setRequestProperty("Accept", "application/json") conn.setRequestProperty("User-Agent", "Mozilla/5.0")
if (conn.responseCode == 200) { val response = conn.inputStream.bufferedReader().readText() val parsed = json.decodeFromString<JsonObject>(response)
// Try to extract product info from the suggestions response val products = parsed["products"]?.jsonObject?.get("hits")?.jsonArray ?: return@withContext null
if (products.isEmpty()) return@withContext null
val firstHit = products[0].jsonObject val productTitle = firstHit["title"]?.jsonPrimitive?.content ?: title val priceValue = firstHit["price"]?.jsonObject val currentPrice = priceValue?.get("sales")?.jsonObject?.get("value") ?.jsonPrimitive?.content?.toFloatOrNull() val originalPrice = priceValue?.get("list")?.jsonObject?.get("value") ?.jsonPrimitive?.content?.toFloatOrNull() val currency = priceValue?.get("sales")?.jsonObject?.get("currency") ?.jsonPrimitive?.content ?: "USD" val productUrl = firstHit["url"]?.jsonPrimitive?.content ?: ""
if (currentPrice == null) return@withContext null
val msrp = originalPrice ?: currentPrice val discountPct = if (msrp > 0 && currentPrice < msrp) { ((1 - currentPrice / msrp) * 100).toInt() } else 0
StorePrice( storeName = "Ubisoft", currentPrice = currentPrice, originalPrice = msrp, discountPercent = discountPct, currency = currency, isFree = currentPrice == 0f, storeUrl = if (productUrl.isNotEmpty()) { val link = if (productUrl.startsWith("http")) productUrl else "https://store.ubisoft.com$productUrl" link } else { val encoded = URLEncoder.encode(title, "UTF-8") "https://store.ubisoft.com/search?q=$encoded" } ) } else null } catch (_: Exception) { null } } }

package com.example.desaappsavaloskoortuzarvargas.data.api

import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import kotlinx.serialization.Serializable
import kotlinx.serialization.json.Json
import java.net.HttpURLConnection
import java.net.URL
import java.net.URLEncoder

// ── Microsoft Store / Xbox PC displaycatalog response models ──

@Serializable
data class MsStoreSearchResponse(
    val Products: List<MsStoreProduct> = emptyList()
)

@Serializable
data class MsStoreProduct(
    val ProductId: String = "",
    val LocalizedProperties: List<MsLocalizedProperty> = emptyList(),
    val DisplaySkuAvailabilities: List<MsDisplaySkuAvailability> = emptyList()
)

@Serializable
data class MsLocalizedProperty(
    val ProductTitle: String = "",
    val ProductDescription: String = ""
)

@Serializable
data class MsDisplaySkuAvailability(
    val Availabilities: List<MsAvailability> = emptyList()
)

@Serializable
data class MsAvailability(
    val OrderManagementData: MsOrderManagementData? = null,
    val Conditions: MsConditions? = null
)

@Serializable
data class MsOrderManagementData(
    val Price: MsPrice? = null
)

@Serializable
data class MsPrice(
    val CurrencyCode: String = "USD",
    val ListPrice: Double = 0.0,
    val MSRP: Double = 0.0,
    val WholesalePrice: Double? = null
)

@Serializable
data class MsConditions(
    val ClientConditions: MsClientConditions? = null
)

@Serializable
data class MsClientConditions(
    val AllowedPlatforms: List<MsPlatform> = emptyList()
)

@Serializable
data class MsPlatform(
    val PlatformName: String = ""
)

/**
 * Service to fetch REAL Argentine prices from the Xbox / Microsoft Store (PC games).
 *
 * Uses Microsoft's public displaycatalog API with market=AR to get
 * the actual price in ARS that an Argentine user sees.
 *
 * Only returns prices for games available on PC (Windows.Desktop platform).
 *
 * Endpoint: https://displaycatalog.mp.microsoft.com/v7.0/products
 */
class XboxPriceService {

    private val json = Json { ignoreUnknownKeys = true }

    /**
     * Search for a PC game on the Microsoft Store and return the Argentine price.
     * Filters results to only include games available on Windows.Desktop.
     */
    suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) {
        try {
            val encoded = URLEncoder.encode(title, "UTF-8")
            val url = URL(
                "https://displaycatalog.mp.microsoft.com/v7.0/products?" +
                "query=$encoded&market=AR&languages=es-AR&mediaGroup=Games&\$top=5"
            )
            val conn = url.openConnection() as HttpURLConnection
            conn.requestMethod = "GET"
            conn.connectTimeout = 10000
            conn.readTimeout = 10000
            conn.setRequestProperty("Accept", "application/json")

            if (conn.responseCode == 200) {
                val response = conn.inputStream.bufferedReader().readText()
                val parsed = json.decodeFromString<MsStoreSearchResponse>(response)

                if (parsed.Products.isEmpty()) return@withContext null

                // Find the best title match that's available on PC
                val match = parsed.Products.firstOrNull { product ->
                    val productTitle = product.LocalizedProperties.firstOrNull()?.ProductTitle ?: ""
                    val isPcGame = product.DisplaySkuAvailabilities.any { sku ->
                        sku.Availabilities.any { avail ->
                            avail.Conditions?.ClientConditions?.AllowedPlatforms?.any {
                                it.PlatformName.contains("Windows", ignoreCase = true) ||
                                it.PlatformName.contains("PC", ignoreCase = true)
                            } == true
                        }
                    }
                    isPcGame && productTitle.contains(title.split(" ").first(), ignoreCase = true)
                } ?: parsed.Products.firstOrNull() ?: return@withContext null

                val productTitle = match.LocalizedProperties.firstOrNull()?.ProductTitle ?: title

                // Get the first available price (prefer PC availability)
                val price = match.DisplaySkuAvailabilities
                    .flatMap { it.Availabilities }
                    .mapNotNull { it.OrderManagementData?.Price }
                    .firstOrNull() ?: return@withContext null

                // Skip if price is 0 and game is not free
                val listPrice = price.ListPrice.toFloat()
                val msrp = price.MSRP.toFloat()
                val isFree = listPrice == 0f && msrp == 0f
                val discountPct = if (msrp > 0 && listPrice < msrp) {
                    ((1 - listPrice / msrp) * 100).toInt()
                } else 0

                StorePrice(
                    storeName = "Xbox / Microsoft",
                    currentPrice = listPrice,
                    originalPrice = msrp,
                    discountPercent = discountPct,
                    currency = price.CurrencyCode,
                    isFree = isFree,
                    storeUrl = "https://www.xbox.com/es-AR/games/store/${match.ProductId}"
                )
            } else null
        } catch (_: Exception) {
            null
        }
    }
}

package com.example.desaappsavaloskoortuzarvargas.data.api

import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import kotlinx.serialization.Serializable
import kotlinx.serialization.json.Json
import java.net.HttpURLConnection
import java.net.URL
import java.net.URLEncoder

// ── Microsoft Store / Xbox PC displaycatalog response models ──

@Serializable
data class MsStoreSearchResponse(
    val Products: List<MsStoreProduct> = emptyList()
)

@Serializable
data class MsStoreProduct(
    val ProductId: String = "",
    val LocalizedProperties: List<MsLocalizedProperty> = emptyList(),
    val DisplaySkuAvailabilities: List<MsDisplaySkuAvailability> = emptyList()
)

@Serializable
data class MsLocalizedProperty(
    val ProductTitle: String = "",
    val ProductDescription: String = ""
)

@Serializable
data class MsDisplaySkuAvailability(
    val Availabilities: List<MsAvailability> = emptyList()
)

@Serializable
data class MsAvailability(
    val OrderManagementData: MsOrderManagementData? = null,
    val Conditions: MsConditions? = null
)

@Serializable
data class MsOrderManagementData(
    val Price: MsPrice? = null
)

@Serializable
data class MsPrice(
    val CurrencyCode: String = "USD",
    val ListPrice: Double = 0.0,
    val MSRP: Double = 0.0,
    val WholesalePrice: Double? = null
)

@Serializable
data class MsConditions(
    val ClientConditions: MsClientConditions? = null
)

@Serializable
data class MsClientConditions(
    val AllowedPlatforms: List<MsPlatform> = emptyList()
)

@Serializable
data class MsPlatform(
    val PlatformName: String = ""
)

/**
 * Service to fetch REAL Argentine prices from the Xbox / Microsoft Store (PC games).
 *
 * Uses Microsoft's public displaycatalog API with market=AR to get
 * the actual price in ARS that an Argentine user sees.
 *
 * Only returns prices for games available on PC (Windows.Desktop platform).
 *
 * Endpoint: https://displaycatalog.mp.microsoft.com/v7.0/products
 */
class XboxPriceService {

    private val json = Json { ignoreUnknownKeys = true }

    /**
     * Search for a PC game on the Microsoft Store and return the Argentine price.
     * Filters results to only include games available on Windows.Desktop.
     */
    suspend fun searchGamePrice(title: String): StorePrice? = withContext(Dispatchers.IO) {
        try {
            val encoded = URLEncoder.encode(title, "UTF-8")
            val url = URL(
                "https://displaycatalog.mp.microsoft.com/v7.0/products?" +
                "query=$encoded&market=AR&languages=es-AR&mediaGroup=Games&\$top=5"
            )
            val conn = url.openConnection() as HttpURLConnection
            conn.requestMethod = "GET"
            conn.connectTimeout = 10000
            conn.readTimeout = 10000
            conn.setRequestProperty("Accept", "application/json")

            if (conn.responseCode == 200) {
                val response = conn.inputStream.bufferedReader().readText()
                val parsed = json.decodeFromString<MsStoreSearchResponse>(response)

                if (parsed.Products.isEmpty()) return@withContext null

                // Find the best title match that's available on PC
                val match = parsed.Products.firstOrNull { product ->
                    val productTitle = product.LocalizedProperties.firstOrNull()?.ProductTitle ?: ""
                    val isPcGame = product.DisplaySkuAvailabilities.any { sku ->
                        sku.Availabilities.any { avail ->
                            avail.Conditions?.ClientConditions?.AllowedPlatforms?.any {
                                it.PlatformName.contains("Windows", ignoreCase = true) ||
                                it.PlatformName.contains("PC", ignoreCase = true)
                            } == true
                        }
                    }
                    isPcGame && productTitle.contains(title.split(" ").first(), ignoreCase = true)
                } ?: parsed.Products.firstOrNull() ?: return@withContext null

                // Get the first available price (prefer PC availability)
                val price = match.DisplaySkuAvailabilities
                    .flatMap { it.Availabilities }
                    .mapNotNull { it.OrderManagementData?.Price }
                    .firstOrNull() ?: return@withContext null

                // Skip if price is 0 and game is not free
                val listPrice = price.ListPrice.toFloat()
                val msrp = price.MSRP.toFloat()
                val isFree = listPrice == 0f && msrp == 0f
                val discountPct = if (msrp > 0 && listPrice < msrp) {
                    ((1 - listPrice / msrp) * 100).toInt()
                } else 0

                StorePrice(
                    storeName = "Xbox / Microsoft",
                    currentPrice = listPrice,
                    originalPrice = msrp,
                    discountPercent = discountPct,
                    currency = price.CurrencyCode,
                    isFree = isFree,
                    storeUrl = if (match.ProductId.isNotEmpty()) {
                        // Xbox Store deep-link using the product ID (bigId)
                        "https://www.xbox.com/games/store/-/${match.ProductId}"
                    } else {
                        val encoded = URLEncoder.encode(title, "UTF-8")
                        "https://www.xbox.com/search?q=$encoded"
                    }
                )
            } else null
        } catch (_: Exception) {
            null
        }
    }
}

