private fun steamImg(gameId: Int): String { // Check if game has a non-empty alternative image (not on Steam) alternativeImages[gameId]?.takeIf { it.isNotEmpty() }?.let { return it } // If game has a Steam App ID, use Steam CDN val appId = steamAppIds[gameId] ?: return "" // No Steam ID → image will be fetched at runtime from the game's store return "https://cdn.akamai.steamstatic.com/steam/apps/$appId/header.jpg" }
