// Games NOT on Steam — image will be fetched at runtime from their store API. // Empty string = runtime fetch from Epic GraphQL (for Epic/HoYoverse games). // Riot DDragon URLs are used for Riot-exclusive games as reliable static fallback. private val alternativeImages = mapOf( // Alan Wake 2 — Epic Games exclusive 9 to "", // League of Legends — Riot Games exclusive 101 to "https://ddragon.leagueoflegends.com/cdn/img/champion/splash/Ahri_0.jpg", // Valorant — Riot Games exclusive 102 to "https://ddragon.leagueoflegends.com/cdn/img/champion/splash/Jett_0.jpg", // Fortnite — Epic Games exclusive 103 to "", // Genshin Impact — HoYoverse / Epic Games 107 to "", // Rocket League — Epic Games exclusive 111 to "", // TFT — Riot Games exclusive 113 to "https://ddragon.leagueoflegends.com/cdn/img/champion/splash/Jinx_0.jpg", // Honkai: Star Rail — HoYoverse / Epic Games 114 to "" )
private fun steamImg(gameId: Int): String { // Check if game has a non-empty alternative image (not on Steam) alternativeImages[gameId]?.takeIf { it.isNotEmpty() }?.let { return it } // If game has a Steam App ID, use Steam CDN val appId = steamAppIds[gameId] ?: return "" // No Steam ID → image will be fetched at runtime from the game's store return "https://cdn.akamai.steamstatic.com/steam/apps/$appId/header.jpg" }
