private fun dlcImg(dlcId: Int): String { val appId = dlcSteamIds[dlcId] ?: return "https://cdn.akamai.steamstatic.com/steam/apps/1245620/header.jpg" return "https://cdn.akamai.steamstatic.com/steam/apps/$appId/header.jpg" }
private fun generateDLCsForGame(gameId: Int): List<DLC> { return dlcData.filter { it.gameId == gameId }.map { dlcInfo -> // Get the parent game to know which platforms are valid val parentGame = popularGames.firstOrNull { it.id == gameId } val dlcPlatforms = parentGame?.platforms ?: listOf("Steam", "Epic Games", "GOG") val basePrices = mapOf( "Steam" to (14.99f + (dlcInfo.id % 10) * 0.5f), "Epic Games" to (13.99f + (dlcInfo.id % 10) * 0.5f), "GOG" to (12.99f + (dlcInfo.id % 10) * 0.5f) ).filter { it.key in dlcPlatforms } DLC( id = dlcInfo.id, name = dlcInfo.name, gameId = gameId, imageUrl = dlcImg(dlcInfo.id), currentPrices = basePrices, historicalDiscount = dlcSteamDbHistoricalDiscount[dlcInfo.id] ?: 0, releaseDate = "2024-${String.format("%02d", (dlcInfo.id % 12) + 1)}-15", description = dlcInfo.desc ) } }
fun generateGames(): List<Game> = popularGames.map { info -> if (info.isF2P) { // F2P games: no prices, just available platforms Game( id = info.id, name = info.name, description = info.description, releaseDate = releaseDates[info.id] ?: "", imageUrl = steamImg(info.id), rating = gameRatings[info.id] ?: 7.0, currentPrices = emptyMap(), historicalDiscount = 0, tags = info.tags, dlcs = emptyList(), availablePlatforms = info.platforms, steamAppId = steamAppIds[info.id] ?: 0 ) } else { val allPrices = mapOf( "Steam" to (29.99f + (info.id % 40) * 0.5f), "Epic Games" to (29.99f + (info.id % 40) * 0.5f - 2f).coerceAtLeast(9.99f), "GOG" to (27.99f + (info.id % 40) * 0.5f), "Xbox / Microsoft" to (29.99f + (info.id % 35) * 0.4f), "EA" to (24.99f + (info.id % 30) * 0.4f), "Ubisoft" to (24.99f + (info.id % 30) * 0.4f), "Battle.net" to (29.99f + (info.id % 35) * 0.3f) ) // Only include prices for platforms where the game is actually available val filteredPrices = allPrices.filter { it.key in info.platforms } // Historical discount: use SteamDB data for Steam games, 0 for non-Steam // (non-Steam games build their history from our own price_history DB) val histDiscount = steamDbHistoricalDiscount[info.id] ?: 0 Game( id = info.id, name = info.name, description = info.description, releaseDate = releaseDates[info.id] ?: "", imageUrl = steamImg(info.id), rating = gameRatings[info.id] ?: 7.0, currentPrices = filteredPrices, historicalDiscount = histDiscount, tags = info.tags, dlcs = generateDLCsForGame(info.id), availablePlatforms = info.platforms, steamAppId = steamAppIds[info.id] ?: 0 ) } }
/** * Get the Steam App IDs mapping (game catalog ID → Steam App ID). * Used by PriceRefreshManager for API lookups. */ fun getSteamAppIdsByName(): Map<String, Int> { return popularGames.mapNotNull { info -> val steamId = steamAppIds[info.id] ?: return@mapNotNull null info.name to steamId }.toMap() }
fun generateNews(): List<News> { val newsList = mutableListOf<News>() val headlines = listOf( "Price dropped to historical low!" to "discount", "New DLC expansion announced" to "update", "Major patch update released" to "update", "Weekend sale event" to "discount", "Limited-time bundle deal" to "discount", "Community event starting soon" to "event", "Next-gen upgrade available" to "update", "Free weekend trial" to "discount" )
for (i in 0 until 60) { val game = popularGames[i % popularGames.size] val (headline, category) = headlines[i % headlines.size] val platform = platforms[i % platforms.size] newsList.add( News( id = i + 1, title = "${game.name} — $headline", content = "Great news for ${game.name} fans! $headline Check out the latest information on $platform. This is a developing story with more details coming soon. Players have been eagerly waiting for this announcement.", imageUrl = steamImg(game.id), date = "2026-${String.format("%02d", (i % 5) + 1)}-${String.format("%02d", (i % 28) + 1)}", gameId = game.id, platform = platform, category = category ) ) } return newsList }
fun generatePriceHistory(): List<PriceHistory> { val history = mutableListOf<PriceHistory>() for (gameIdx in 0 until 20) { val game = popularGames[gameIdx] val basePrice = 29.99f + (game.id % 40) * 0.5f for (month in 1..12) { for (platform in platforms) { val discountPct = ((month * 7 + platforms.indexOf(platform) * 11) % 80) val price = basePrice * (1f - discountPct / 100f) history.add( PriceHistory( gameId = game.id, platform = platform, price = price, discount = discountPct, date = "2025-${String.format("%02d", month)}-15", isHistoricalLowest = discountPct >= 70 ) ) } } } return history } }

package com.example.desaappsavaloskoortuzarvargas.data.repository

import com.example.desaappsavaloskoortuzarvargas.data.api.PriceRefreshManager
import com.example.desaappsavaloskoortuzarvargas.data.catalog.GameCatalog
import com.example.desaappsavaloskoortuzarvargas.data.local.dao.GamePriceDao
import com.example.desaappsavaloskoortuzarvargas.data.local.entity.GamePriceEntity
import com.example.desaappsavaloskoortuzarvargas.domain.model.DiscountedGame
import com.example.desaappsavaloskoortuzarvargas.domain.model.OfferType
import com.example.desaappsavaloskoortuzarvargas.domain.repository.DiscountRepository

/**
 * Discount repository that reads REAL data from cached API prices.
 * No more mock discounts — all data comes from actual store APIs.
 */
class DiscountRepositoryImpl(
    private val gamePriceDao: GamePriceDao,
    private val priceRefreshManager: PriceRefreshManager
) : DiscountRepository {

    // Cache the game catalog for lookups
    private val catalogGames by lazy { GameCatalog.generateGames() }
    private val catalogByName by lazy { catalogGames.associateBy { it.name } }

    override suspend fun getCurrentDiscounts(): Result<List<DiscountedGame>> = try {
        val discountedPrices = gamePriceDao.getDiscountedPrices()
        val result = discountedPrices.mapNotNull { entity -> toDiscountedGame(entity) }
            .sortedByDescending { it.discountPercentage }
        Result.success(result)
    } catch (e: Exception) { Result.failure(e) }

    override suspend fun getFavoriteDiscounts(favoriteGameIds: List<Int>): Result<List<DiscountedGame>> = try {
        val favoriteNames = favoriteGameIds.mapNotNull { id ->
            catalogGames.firstOrNull { it.id == id }?.name
        }.toSet()
        val discountedPrices = gamePriceDao.getDiscountedPrices()
        val result = discountedPrices
            .filter { it.gameName in favoriteNames }
            .mapNotNull { entity -> toDiscountedGame(entity) }
            .sortedByDescending { it.discountPercentage }
        Result.success(result)
    } catch (e: Exception) { Result.failure(e) }

    override suspend fun getHistoricalLowDiscounts(): Result<List<DiscountedGame>> = try {
        val discountedPrices = gamePriceDao.getDiscountedPrices()
        val result = discountedPrices.mapNotNull { entity ->
            val game = toDiscountedGame(entity) ?: return@mapNotNull null
            val isHistLow = priceRefreshManager.isHistoricalLow(
                entity.gameName, entity.storeName, entity.currentPrice
            )
            if (isHistLow) game.copy(isHistoricalLowest = true) else null
        }.sortedByDescending { it.discountPercentage }
        Result.success(result)
    } catch (e: Exception) { Result.failure(e) }

    override suspend fun getFreeGames(): Result<List<DiscountedGame>> = try {
        // Temporarily free games from API (currently free, normally paid)
        val freePrices = gamePriceDao.getFreePrices()
        val tempFree = freePrices
            .filter { it.retailPrice > 0f } // Was paid, now free → temporarily free
            .mapNotNull { entity ->
                toDiscountedGame(entity)?.copy(
                    isFree = true,
                    isTemporarilyFree = true,
                    discountPercentage = 100,
                    offerType = OfferType.TEMPORARILY_FREE
                )
            }

        // F2P games from catalog (always free)
        val f2pGames = catalogGames.filter {
            it.currentPrices.isEmpty() && it.availablePlatforms.isNotEmpty()
        }.map { game ->
            DiscountedGame(
                gameId = game.id,
                gameName = game.name,
                imageUrl = game.imageUrl,
                platform = game.availablePlatforms.firstOrNull() ?: "PC",
                originalPrice = 0f,
                currentPrice = 0f,
                discountPercentage = 100,
                isFree = true,
                isF2P = true,
                isTemporarilyFree = false,
                offerType = OfferType.F2P,
                tags = game.tags
            )
        }

        Result.success(tempFree + f2pGames)
    } catch (e: Exception) { Result.failure(e) }

    override suspend fun getDiscountsByPlatform(platform: String): Result<List<DiscountedGame>> = try {
        val discountedPrices = gamePriceDao.getDiscountedPrices()
        val result = discountedPrices
            .filter { it.storeName.equals(platform, ignoreCase = true) }
            .mapNotNull { entity -> toDiscountedGame(entity) }
            .sortedByDescending { it.discountPercentage }
        Result.success(result)
    } catch (e: Exception) { Result.failure(e) }

    /**
     * Get games that had a permanent base price reduction (not a sale).
     */
    override suspend fun getPriceDrops(): Result<List<DiscountedGame>> = try {
        val allPrices = gamePriceDao.getAllPrices()
        val result = allPrices.mapNotNull { entity ->
            val previousRetail = priceRefreshManager.detectPriceDrop(
                entity.gameName, entity.storeName, entity.retailPrice
            ) ?: return@mapNotNull null
            toDiscountedGame(entity)?.copy(
                offerType = OfferType.PERMANENT_PRICE_DROP,
                previousBasePrice = previousRetail
            )
        }
        Result.success(result)
    } catch (e: Exception) { Result.failure(e) }

    /**
     * Convert a GamePriceEntity to a DiscountedGame using catalog data for metadata.
     */
    private suspend fun toDiscountedGame(entity: GamePriceEntity): DiscountedGame? {
        val catalogGame = catalogByName[entity.gameName] ?: return null
        val isHistLow = try {
            priceRefreshManager.isHistoricalLow(entity.gameName, entity.storeName, entity.currentPrice)
        } catch (_: Exception) { false }

        return DiscountedGame(
            gameId = catalogGame.id,
            gameName = entity.gameName,
            imageUrl = catalogGame.imageUrl,
            platform = entity.storeName,
            originalPrice = entity.retailPrice,
            currentPrice = entity.currentPrice,
            discountPercentage = entity.savings.toInt(),
            isFree = entity.currentPrice == 0f,
            isF2P = false,
            isTemporarilyFree = entity.currentPrice == 0f && entity.retailPrice > 0f,
            isHistoricalLowest = isHistLow,
            tags = catalogGame.tags,
            offerType = if (entity.currentPrice == 0f && entity.retailPrice > 0f) {
                OfferType.TEMPORARILY_FREE
            } else {
                OfferType.SALE
            },
            endTimestamp = entity.discountEndTimestamp
        )
    }
}

