@Composable
fun MainScreen() {
    val navState = remember { NavigationStateManager() }
    val currentTab by navState.currentTab.collectAsState()
    val selectedGame by navState.selectedGame.collectAsState()
    val selectedNews by navState.selectedNews.collectAsState()

    val gameRepository = ServiceLocator.gameRepository
    val newsRepository = ServiceLocator.newsRepository
    val discountRepository = ServiceLocator.discountRepository
    val userSettingsRepository = ServiceLocator.userSettingsRepository
    val priceRefreshManager = ServiceLocator.priceRefreshManager
    val dolarService = ServiceLocator.dolarService
    val epicPriceService = ServiceLocator.epicPriceService
    val database = ServiceLocator.database
    val connectivityObserver = ServiceLocator.connectivityObserver


    val gamesViewModel = remember {
        GamesViewModel(
            GetAllGamesUseCase(gameRepository),
            GetGameByIdUseCase(gameRepository),
            SearchGamesUseCase(gameRepository),
            AddToFavoritesUseCase(gameRepository),
            RemoveFromFavoritesUseCase(gameRepository),
            GetFavoritesUseCase(gameRepository),
            GetPriceHistoryUseCase(gameRepository),
            GetGamesByTagUseCase(gameRepository),
            priceRefreshManager,
            dolarService,
            epicPriceService,
            database.gameImageDao(),
            connectivityObserver
        )
    }

    val newsViewModel = remember {
        NewsViewModel(
            GetAllNewsUseCase(newsRepository),
            GetNewsByGameIdUseCase(newsRepository),
            GetNewsByFavoritesUseCase(newsRepository),
            GetFavoritesUseCase(gameRepository)
        )
    }

    val offersViewModel = remember {
        OffersViewModel(
            GetCurrentDiscountsUseCase(discountRepository),
            GetFavoriteDiscountsUseCase(discountRepository),
            GetHistoricalLowDiscountsUseCase(discountRepository),
            GetFreeGamesUseCase(discountRepository),
            GetFavoritesUseCase(gameRepository),
            GetPriceDropsUseCase(discountRepository)
        )
    }

    val settingsViewModel = remember {
        SettingsViewModel(
            GetUserSettingsUseCase(userSettingsRepository),
            UpdateUserNameUseCase(userSettingsRepository),
            UpdateEmailUseCase(userSettingsRepository),
            UpdateCountryUseCase(userSettingsRepository),
            UpdateLanguageUseCase(userSettingsRepository),
            SetGlobalNotificationsUseCase(userSettingsRepository),
            UpdateGameNotificationPrefUseCase(userSettingsRepository),
            GetInAppNotificationsUseCase(userSettingsRepository),
            GetUnreadNotificationCountUseCase(userSettingsRepository),
            MarkNotificationReadUseCase(userSettingsRepository),
            GenerateDiscountNotificationsUseCase(userSettingsRepository),
            GetFavoritesUseCase(gameRepository)
        )
    }

    val unreadCount by settingsViewModel.unreadCount.collectAsState()
    val isOnline by gamesViewModel.isOnline.collectAsState()

    // Start periodic background price refresh and ensure all games are cached
    LaunchedEffect(Unit) {
        val steamIdMap = com.example.desaappsavaloskoortuzarvargas.data.catalog.GameCatalog.getSteamAppIdsByName()
        priceRefreshManager.setSteamAppIds(steamIdMap)
        priceRefreshManager.startPeriodicRefresh()
        // Ensure all catalog games have prices cached (for offers section)
        val allNames = com.example.desaappsavaloskoortuzarvargas.data.catalog.GameCatalog.generateGames()
            .filter { !it.tags.contains("Free2Play") }
            .map { it.name }
        priceRefreshManager.ensureAllGamesCached(allNames) {
            // Reload offers progressively after each batch so the user
            // sees results appearing instead of an empty screen
            offersViewModel.loadCurrentDiscounts()
            offersViewModel.loadFreeGames()
        }
        // Final reload when everything is done
        offersViewModel.loadCurrentDiscounts()
        offersViewModel.loadFreeGames()
    }

    // Preserve catalog scroll position across detail screen navigation
    val catalogListState = rememberLazyListState()

    // Back navigation: from detail screens go back to list, from non-home tabs go to home (Catalog)
    BackHandler(enabled = navState.isBackEnabled) {
        navState.handleBack()
    }

    // Detail screens
    when {
        selectedGame != null -> {
            GameDetailScreen(
                game = selectedGame!!,
                viewModel = gamesViewModel,
                onBackClick = { navState.clearSelectedGame() },
                onFavoriteClick = { game ->
                    gamesViewModel.toggleFavorite(game)
                    navState.updateSelectedGame(game.copy(isFavorite = !game.isFavorite))
                }
            )
            return
        }
        selectedNews != null -> {
            NewsDetailScreen(
                news = selectedNews!!,
                onBackClick = { navState.clearSelectedNews() }
            )
            return
        }
    }

    Scaffold(
        modifier = Modifier.fillMaxSize(),
        topBar = {
            // Offline banner
            AnimatedVisibility(
                visible = !isOnline,
                enter = expandVertically(),
                exit = shrinkVertically()
            ) {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .background(Color(0xFFFF6B00))
                        .padding(horizontal = 16.dp, vertical = 10.dp),
                    horizontalArrangement = Arrangement.Center,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Icon(
                        Icons.Filled.SignalWifiOff,
                        contentDescription = null,
                        tint = Color.White,
                        modifier = Modifier.size(18.dp)
                    )
                    Text(
                        text = stringResource(R.string.offline_banner),
                        color = Color.White,
                        style = MaterialTheme.typography.bodySmall,
                        fontWeight = FontWeight.Bold,
                        modifier = Modifier.padding(start = 8.dp)
                    )
                }
            }
        },
        bottomBar = {
            NavigationBar {
                NavigationBarItem(
                    icon = {
                        Icon(
                            Icons.Filled.LocalOffer,
                            contentDescription = stringResource(R.string.nav_offers)
                        )
                    },
                    label = { Text(stringResource(R.string.nav_offers)) },
                    selected = currentTab == NavigationStateManager.TAB_OFFERS,
                    colors = NavigationBarItemDefaults.colors(
                        selectedIconColor = AccentCyan,
                        unselectedIconColor = AccentCyan,
                        selectedTextColor = NavItemLabelSelectedColor,
                        unselectedTextColor = NavItemLabelColor
                    ),
                    onClick = { navState.selectTab(NavigationStateManager.TAB_OFFERS) }
                )
                NavigationBarItem(
                    icon = {
                        Icon(
                            Icons.Filled.Search,
                            contentDescription = stringResource(R.string.nav_catalog)
                        )
                    },
                    label = { Text(stringResource(R.string.nav_catalog)) },
                    selected = currentTab == NavigationStateManager.TAB_CATALOG,
                    colors = NavigationBarItemDefaults.colors(
                        selectedIconColor = AccentCyan,
                        unselectedIconColor = AccentCyan,
                        selectedTextColor = NavItemLabelSelectedColor,
                        unselectedTextColor = NavItemLabelColor
                    ),
                    onClick = { navState.selectTab(NavigationStateManager.TAB_CATALOG) }
                )
                NavigationBarItem(
                    icon = {
                        Icon(
                            Icons.Filled.Favorite,
                            contentDescription = stringResource(R.string.nav_favorites)
                        )
                    },
                    label = { Text(stringResource(R.string.nav_favorites)) },
                    selected = currentTab == NavigationStateManager.TAB_FAVORITES,
                    colors = NavigationBarItemDefaults.colors(
                        selectedIconColor = AccentCyan,
                        unselectedIconColor = AccentCyan,
                        selectedTextColor = NavItemLabelSelectedColor,
                        unselectedTextColor = NavItemLabelColor
                    ),
                    onClick = {
                        navState.selectTab(NavigationStateManager.TAB_FAVORITES)
                        gamesViewModel.loadFavorites()
                    }
                )
                NavigationBarItem(
                    icon = {
                        Icon(
                            Icons.Filled.Newspaper,
                            contentDescription = stringResource(R.string.nav_news)
                        )
                    },
                    label = { Text(stringResource(R.string.nav_news)) },
                    selected = currentTab == NavigationStateManager.TAB_NEWS,
                    colors = NavigationBarItemDefaults.colors(
                        selectedIconColor = AccentCyan,
                        unselectedIconColor = AccentCyan,
                        selectedTextColor = NavItemLabelSelectedColor,
                        unselectedTextColor = NavItemLabelColor
                    ),
                    onClick = { navState.selectTab(NavigationStateManager.TAB_NEWS) }
                )
                NavigationBarItem(
                    icon = {
                        BadgedBox(
                            badge = {
                                if (unreadCount > 0) {
                                    Badge { Text("$unreadCount") }
                                }
                            }
                        ) {
                            Icon(
                                Icons.Filled.Settings,
                                contentDescription = stringResource(R.string.nav_settings)
                            )
                        }
                    },
                    label = { Text(stringResource(R.string.nav_settings)) },
                    selected = currentTab == NavigationStateManager.TAB_SETTINGS,
                    colors = NavigationBarItemDefaults.colors(
                        selectedIconColor = AccentCyan,
                        unselectedIconColor = AccentCyan,
                        selectedTextColor = NavItemLabelSelectedColor,
                        unselectedTextColor = NavItemLabelColor
                    ),
                    onClick = {
                        navState.selectTab(NavigationStateManager.TAB_SETTINGS)
                        settingsViewModel.refreshNotifications()
                    }
                )
            }
        }
    ) { paddingValues ->
        val dolarRate by gamesViewModel.dolarTarjetaRate.collectAsState()
        when (currentTab) {
            NavigationStateManager.TAB_OFFERS -> OffersScreen(
                viewModel = offersViewModel,
                onDiscountSelected = { discount ->
                    val game = gamesViewModel.allGames.value.find { it.id == discount.gameId }
                    if (game != null) {
                        navState.selectGame(game)
                    }
                },
                modifier = Modifier.padding(paddingValues),
                dolarRate = dolarRate,
                convertToArs = { gamesViewModel.convertToArs(it) }
            )
            NavigationStateManager.TAB_CATALOG -> GamesScreen(
                viewModel = gamesViewModel,
                onGameSelected = { navState.selectGame(it) },
                modifier = Modifier.padding(paddingValues),
                listState = catalogListState
            )
            NavigationStateManager.TAB_FAVORITES -> FavoritesScreen(
                viewModel = gamesViewModel,
                settingsViewModel = settingsViewModel,
                onGameSelected = { navState.selectGame(it) },
                modifier = Modifier.padding(paddingValues)
            )
            NavigationStateManager.TAB_NEWS -> NewsScreen(
                viewModel = newsViewModel,
                onNewsSelected = { navState.selectNews(it) },
                onGameClicked = { gameId ->
                    val game = gamesViewModel.allGames.value.find { it.id == gameId }
                    if (game != null) {
                        navState.selectGame(game)
                    }
                },
                modifier = Modifier.padding(paddingValues)
            )
            NavigationStateManager.TAB_SETTINGS -> SettingsScreen(
                settingsViewModel = settingsViewModel,
                modifier = Modifier.padding(paddingValues)
            )
        }
    }
}

package com.example.desaappsavaloskoortuzarvargas.presentation.navigation

import com.example.desaappsavaloskoortuzarvargas.domain.model.Game
import com.example.desaappsavaloskoortuzarvargas.domain.model.News
import org.junit.Assert.*
import org.junit.Before
import org.junit.Test

class NavigationStateManagerTest {

    private lateinit var navState: NavigationStateManager

    private val sampleGame = Game(
        id = 1, name = "Test Game", description = "Desc", releaseDate = "2024",
        imageUrl = "url", rating = 8.0, currentPrices = mapOf("Steam" to 29.99f)
    )

    private val sampleGame2 = Game(
        id = 2, name = "Test Game 2", description = "Desc2", releaseDate = "2025",
        imageUrl = "url2", rating = 9.0, currentPrices = mapOf("Epic" to 19.99f)
    )

    private val sampleNews = News(
        id = 1, title = "Test News", content = "Content",
        imageUrl = "url", date = "2024-01-01", gameId = 1,
        platform = "Steam", category = "Review"
    )

    @Before
    fun setup() {
        navState = NavigationStateManager()
    }

    // ==================== Initial State ====================

    @Test
    fun `initial tab is catalog (home)`() {
        assertEquals(NavigationStateManager.TAB_CATALOG, navState.currentTab.value)
    }

    @Test
    fun `initial selected game is null`() {
        assertNull(navState.selectedGame.value)
    }

    @Test
    fun `initial selected news is null`() {
        assertNull(navState.selectedNews.value)
    }

    @Test
    fun `back is not enabled on initial state`() {
        assertFalse(navState.isBackEnabled)
    }

    // ==================== Tab Navigation ====================

    @Test
    fun `selectTab changes current tab`() {
        navState.selectTab(NavigationStateManager.TAB_OFFERS)
        assertEquals(NavigationStateManager.TAB_OFFERS, navState.currentTab.value)
    }

    @Test
    fun `selectTab to non-home tab enables back`() {
        navState.selectTab(NavigationStateManager.TAB_SETTINGS)
        assertTrue(navState.isBackEnabled)
    }

    @Test
    fun `selectTab to home tab disables back`() {
        navState.selectTab(NavigationStateManager.TAB_OFFERS)
        navState.selectTab(NavigationStateManager.TAB_CATALOG)
        assertFalse(navState.isBackEnabled)
    }

    @Test
    fun `navigate through all tabs`() {
        val tabs = listOf(
            NavigationStateManager.TAB_OFFERS,
            NavigationStateManager.TAB_CATALOG,
            NavigationStateManager.TAB_FAVORITES,
            NavigationStateManager.TAB_NEWS,
            NavigationStateManager.TAB_SETTINGS
        )
        for (tab in tabs) {
            navState.selectTab(tab)
            assertEquals(tab, navState.currentTab.value)
        }
    }

    // ==================== Game Selection ====================

    @Test
    fun `selectGame sets selected game`() {
        navState.selectGame(sampleGame)
        assertEquals(sampleGame, navState.selectedGame.value)
    }

    @Test
    fun `selectGame enables back`() {
        navState.selectGame(sampleGame)
        assertTrue(navState.isBackEnabled)
    }

    @Test
    fun `clearSelectedGame clears game`() {
        navState.selectGame(sampleGame)
        navState.clearSelectedGame()
        assertNull(navState.selectedGame.value)
    }

    @Test
    fun `updateSelectedGame replaces game`() {
        navState.selectGame(sampleGame)
        val updated = sampleGame.copy(isFavorite = true)
        navState.updateSelectedGame(updated)
        assertEquals(true, navState.selectedGame.value?.isFavorite)
    }

    // ==================== News Selection ====================

    @Test
    fun `selectNews sets selected news`() {
        navState.selectNews(sampleNews)
        assertEquals(sampleNews, navState.selectedNews.value)
    }

    @Test
    fun `selectNews enables back`() {
        navState.selectNews(sampleNews)
        assertTrue(navState.isBackEnabled)
    }

    @Test
    fun `clearSelectedNews clears news`() {
        navState.selectNews(sampleNews)
        navState.clearSelectedNews()
        assertNull(navState.selectedNews.value)
    }

    // ==================== Back Handler ====================

    @Test
    fun `handleBack from game detail clears game and returns true`() {
        navState.selectGame(sampleGame)
        val consumed = navState.handleBack()
        assertTrue(consumed)
        assertNull(navState.selectedGame.value)
    }

    @Test
    fun `handleBack from news detail clears news and returns true`() {
        navState.selectNews(sampleNews)
        val consumed = navState.handleBack()
        assertTrue(consumed)
        assertNull(navState.selectedNews.value)
    }

    @Test
    fun `handleBack from non-home tab goes to home and returns true`() {
        navState.selectTab(NavigationStateManager.TAB_SETTINGS)
        val consumed = navState.handleBack()
        assertTrue(consumed)
        assertEquals(NavigationStateManager.TAB_CATALOG, navState.currentTab.value)
    }

    @Test
    fun `handleBack from home tab returns false`() {
        val consumed = navState.handleBack()
        assertFalse(consumed)
    }

    @Test
    fun `handleBack prioritizes game over news`() {
        navState.selectNews(sampleNews)
        navState.selectGame(sampleGame)
        navState.handleBack()
        // Game should be cleared first, news still there
        assertNull(navState.selectedGame.value)
        assertNotNull(navState.selectedNews.value)
    }

    @Test
    fun `handleBack prioritizes game over tab change`() {
        navState.selectTab(NavigationStateManager.TAB_OFFERS)
        navState.selectGame(sampleGame)
        navState.handleBack()
        // Game cleared, tab stays on offers
        assertNull(navState.selectedGame.value)
        assertEquals(NavigationStateManager.TAB_OFFERS, navState.currentTab.value)
    }

    @Test
    fun `handleBack prioritizes news over tab change`() {
        navState.selectTab(NavigationStateManager.TAB_NEWS)
        navState.selectNews(sampleNews)
        navState.handleBack()
        // News cleared, tab stays
        assertNull(navState.selectedNews.value)
        assertEquals(NavigationStateManager.TAB_NEWS, navState.currentTab.value)
    }

    @Test
    fun `multiple backs from game on non-home tab returns to home`() {
        navState.selectTab(NavigationStateManager.TAB_FAVORITES)
        navState.selectGame(sampleGame)

        // First back: clears game, returns to favorites tab
        assertTrue(navState.handleBack())
        assertNull(navState.selectedGame.value)
        assertEquals(NavigationStateManager.TAB_FAVORITES, navState.currentTab.value)

        // Second back: returns to catalog (home)
        assertTrue(navState.handleBack())
        assertEquals(NavigationStateManager.TAB_CATALOG, navState.currentTab.value)

        // Third back: nothing to do, returns false (app should exit)
        assertFalse(navState.handleBack())
    }

    @Test
    fun `back from each tab goes to home`() {
        val nonHomeTabs = listOf(
            NavigationStateManager.TAB_OFFERS,
            NavigationStateManager.TAB_FAVORITES,
            NavigationStateManager.TAB_NEWS,
            NavigationStateManager.TAB_SETTINGS
        )
        for (tab in nonHomeTabs) {
            navState.selectTab(tab)
            assertTrue(navState.handleBack())
            assertEquals(NavigationStateManager.TAB_CATALOG, navState.currentTab.value)
        }
    }

    // ==================== Constants ====================

    @Test
    fun `tab constants have correct values`() {
        assertEquals(0, NavigationStateManager.TAB_OFFERS)
        assertEquals(1, NavigationStateManager.TAB_CATALOG)
        assertEquals(2, NavigationStateManager.TAB_FAVORITES)
        assertEquals(3, NavigationStateManager.TAB_NEWS)
        assertEquals(4, NavigationStateManager.TAB_SETTINGS)
    }

    @Test
    fun `default home tab is catalog`() {
        assertEquals(NavigationStateManager.TAB_CATALOG, NavigationStateManager.DEFAULT_HOME_TAB)
    }

    @Test
    fun `custom home tab works`() {
        val customNav = NavigationStateManager(homeTab = NavigationStateManager.TAB_OFFERS)
        assertEquals(NavigationStateManager.TAB_OFFERS, customNav.currentTab.value)
        assertFalse(customNav.isBackEnabled)

        customNav.selectTab(NavigationStateManager.TAB_CATALOG)
        assertTrue(customNav.isBackEnabled)
        customNav.handleBack()
        assertEquals(NavigationStateManager.TAB_OFFERS, customNav.currentTab.value)
    }

    // ==================== Edge Cases ====================

    @Test
    fun `isBackEnabled with game selected on home tab`() {
        navState.selectGame(sampleGame)
        assertTrue(navState.isBackEnabled)
    }

    @Test
    fun `clearing game on home tab disables back`() {
        navState.selectGame(sampleGame)
        navState.clearSelectedGame()
        assertFalse(navState.isBackEnabled)
    }

    @Test
    fun `selecting different games updates correctly`() {
        navState.selectGame(sampleGame)
        assertEquals(sampleGame.id, navState.selectedGame.value?.id)
        navState.selectGame(sampleGame2)
        assertEquals(sampleGame2.id, navState.selectedGame.value?.id)
    }
}
